    // .............
    // #1: Start2

    void passage1_Init()
    {
        this.Passages[@"Start2"] = new StoryPassage(@"Start2", new string[] { "ck", "updated", }, passage1_Main);
    }

    IStoryThread passage1_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("LE SECRET DE MON PÈRE");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Choisissez un Scénario ");
            if (Vars.players == 2)
            {
                yield return text("pour 2 joueurs :");
            }
            if (Vars.players == 3)
            {
                yield return text("pour 3 joueurs :");
            }
            if (Vars.players == 4)
            {
                yield return text("pour 4 joueurs :");
            }
            if (Vars.players == 5)
            {
                yield return text("pour 5 joueurs :");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Temps de Guerre", "NoLink", null);
        yield return lineBreak();
        yield return link("La Peur de l\'Inconnu", "NoLink", null);
        yield return lineBreak();
        yield return link("Le Fardeau de la Maladie", "Preparations-TCOD", null);
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Pour une explication du fonctionnement de ce livret Histoire ");
            yield return text("<sprite=\"StorybookToken\" index=0>");
            yield return text(",");
        }
        yield return text(" ");
        yield return link("cliquez ici.", "StoryBook", null);
        yield return lineBreak();
        Vars.tracker = 0;
        yield break;
    }


    // .............
    // #2: Fever1

    void passage2_Init()
    {
        this.Passages[@"Fever1"] = new StoryPassage(@"Fever1", new string[] { "HUB", "revised", }, passage2_Main);
    }

    IStoryThread passage2_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("FIÈVRE JAUNE - Début de cycle");
        }
        yield return text("_round: \'Génération I -Début de cycle\'");
        yield return lineBreak();
        Vars.round = 1;
        yield return lineBreak();
        if (Vars.tcodgen1 == 0 || Vars.tcodgen1 == "")
        {
            using (styleScope("setupStyle", true))
            {
                using (styleScope("bold", true))
                {
                    yield return text("MISE EN PLACE");
                }
                Vars._SetupImage = "StartPlayerToken";

                yield return lineBreak();
                yield return text("Allez à la section ");
                using (styleScope("bold", true))
                {
                    yield return text("Le Fardeau de la Maladie");
                }
                yield return text("des Chroniques de la ville. Allez à la ");
                using (styleScope("bold", true))
                {
                    yield return text("page 1");
                }
                using (styleScope("italic", true))
                {
                    yield return text("(ceci est noté par le symbole correspondant au Fardeau de la Maladie :");
                }
                yield return text("<sprite=\"S1_ScenarioIcon\" index=0>");
