    // .............
    // #5: Scenario5Start

    void passage5_Init()
    {
        this.Passages[@"Scenario5Start"] = new StoryPassage(@"Scenario5Start", new string[] { "INTRO", "revised", }, passage5_Main);
    }

    IStoryThread passage5_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION I :");
            yield return lineBreak();
            yield return text("Fièvre jaune");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"En vue de profiter de leur considérable héritage, les frères et sœurs arrivèrent dans l'indifférence de cet arrière-pays boueux et terne, au ciel recouvert de gris. L'air était saturé d'humidité, mais l'orage ne parvenait pas à éclater, comme s'il se réservait pour les circonstances plus graves dans lesquelles les frères et sœurs allaient se retrouver.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"En arrivant au village, ils ne purent que remarquer une puanteur tenace. Dans les rues, des attelages de chevaux tiraient des wagonnets de charbon comme des corbillards silencieux. Des paysans émaciés protégeaient leur visage de la poussière noire, visiblement peu étonnés du spectacle, puis revenaient à leurs sombres besognes comme si de rien n'était. Le long de la route principale, plusieurs charrettes étaient recouvertes de bâches. On apercevait çà et là un pied gris pendouillant d'un pan de toile crevé.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La Fièvre jaune avait touché le village et, pendant plusieurs semaines, à chaque visite, les jeunes héritiers devaient garder un mouchoir de tissu sur leur bouche et leurs narines afin de se protéger des miasmes. Bien qu'ils fussent réticents à l'admettre, ceci était la toile parfaite pour la concrétisation de l'œuvre macabre de leur père.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Bien qu'au village, l'humeur fusse à la morosité et à la méfiance, les jeunes entrepreneurs voyaient du potentiel dans ces ruelles assombries. Un individu particulièrement ambitieux pouvait transformer ce village terne en cité flamboyante. Un aristocrate avec suffisamment d'argent à dépenser pouvait même prétendre à en prendre la tête...");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La fratrie surveillait la campagne morne, chacun à l'abri des grilles de fer forgé de son domaine, observant chaque lambeau de brouillard se dérouler dans la vallée. Les citadins tremblèrent lorsque plusieurs rires leur parvinrent, à l'unisson, des collines environnantes. Les héritiers étaient impatients de se remettre à l'œuvre de leur père !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "Dubious", null);
        yield return lineBreak();
        Vars.wolves = macros1.either("malfaisante", "bienfaisante");
        if (Vars.wolves == "bienfaisante")
        {
            Vars.hunters = "malfaisante";
        }
        if (Vars.wolves == "malfaisante")
        {
            Vars.hunters = "malfaisante";
        }
        Vars.tcodgen1 = 0;
        Vars.creepy4 = 0;
        Vars.sane3 = 0;
        yield break;
    }


