    IStoryThread passage6_Main()
    {
        yield return text("Avant de résoudre cet événement, tous les joueurs doivent accomplir toutes les ac" +
            "tions de début de manche.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("_round: \'Génération I - Début de la fin de cycle\'");
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("La ville a besoin de quelqu\'un à sa tête");
        }
        yield return lineBreak();
        yield return text(@"Après la mort malencontreuse du maire actuel (et celle des trois précédents), la ville se retrouva une fois de plus dans la tourmente politique. Des hommes d'affaires à la médiocrité affligeante se jetèrent dans l'arène, mais la famille perçut le désespoir de la ville tandis qu'elle cherchait comment aller de l'avant. Ayant été élevés dans un esprit de compétition amicale, les héritiers décidèrent que la gouvernance de la ville serait un loisir amusant pour la famille. Frères et sœurs useraient de leur influence pour faire pencher l'élection en leur faveur.");
        yield return lineBreak();
        Vars.tcodgen1 = 0;
        yield return lineBreak();
        yield return text("L\'affaire n\'était pas anodine, car le nouveau maire ");
        using (styleScope("bold", true))
        {
            yield return text("gagnerait immédiatement 3 PV");
        }
        yield return text(" ");
        yield return text("et prendrait la décision de faire construire une ");
        using (styleScope("bold", true))
        {
            yield return text("banque");
        }
        yield return text(" ");
        using (styleScope("italic", true))
        {
            yield return text("(pour obtenir des revenus supplémentaires)");
        }
        yield return text(", ou une ");
        using (styleScope("bold", true))
        {
            yield return text("bibliothèque");
        }
        yield return text(" ");
        using (styleScope("italic", true))
        {
            yield return text("(pour obtenir des connaissances supplémentaires)");
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "S5Special1a", null);
        yield return lineBreak();
        yield break;
    }


