    // #12: Hospitalintro

    void passage12_Init()
    {
        this.Passages[@"Hospitalintro"] = new StoryPassage(@"Hospitalintro", new string[] { "INTRO", "revised", "rev2", "rev3", }, passage12_Main);
    }

    IStoryThread passage12_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION II :");
            yield return lineBreak();
            yield return text("Fleurir malgré l\'adversité");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"On dit que l'arrivée du printemps, surveillée par les névés des sommets carpatiens, est un spectacle merveilleux. Une simple excursion par ces collines arrondies, par les chemins qui fendent les hautes herbes émeraude, voilà qui, si l'on en croit la sagesse populaire, revigore le voyageur solitaire. Dans une telle escapade, il est courant de humer le parfum d'un pain fraîchement cuit, d'entendre le clapotis vigoureux des ruisseaux à l'eau siphonnée par des racines couvertes de mousse, d'assister à des crépuscules baignés d'une lumière mielleuse. À l'exception de la mauvaise saison, tout en ce pays respire l'insouciance, la simplicité heureuse qui sait enflammer la torche de la poésie dans les esprits sombres.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le retour des scientifiques coïncida avec celui du printemps ; alignement certes fortuit, mais fort à propos, puisque leurs prédécesseurs avaient, de par leurs actions, permis à la ville de se relever. La chape grisâtre qui avait un jour régné sur la bourgade avait été levée, et désormais le soleil brillait, tout comme les azalées et les crocus qui, à présent, ornaient les massifs aux pieds des fenêtres.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le nouvel hôpital était devenu un flambeau d'espérance pour les citadins, la ville ayant pu essuyer les ravages de maladies alors même que les journaux décrivaient l'atmosphère putride et funeste des villes environnantes. Grâce au travail de leurs géniteurs, leurs enfants héritèrent de postes honoraires à la direction de l'hôpital. Malheureusement, refuser ces postes était tout à fait impossible. Être si proche de la maladie s'avéra providentiel pour tâter et repousser les limites de la science.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cette avancée miraculeuse dans le domaine de la prévention des maladies attira l\'" +
            "attention non seulement du diocèse, mais aussi de la communauté scientifique, qu" +
            "i essaya de reproduire le succès de ");
        yield return text(Vars.townname);
        yield return text(". Des rumeurs coururent à propos d\'une université financée par le gouvernement, e" +
            "t cette perspective causa émoi et tension pour le clergé comme pour les citadins" +
            ", ces derniers s\'étant habitués à leur existence calme et bucolique.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les progrès possibles, et l'exploitation de ceux-ci, semblaient sans limites. Mais les ambitions ingénieuses et peu orthodoxes de cette jeune génération s'avéreraient-elle trop étranges pour les érudits circonspects ? Leur volonté indomptable serait-elle brisée par les rejets successifs de leurs pairs ?");
        yield return lineBreak();
        if (Vars.building == "bank")
        {
            Vars.hos = 4;
        }
