    IStoryThread passage14_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III :");
            yield return lineBreak();
            yield return text("L\'université progresse");
        }
        yield return lineBreak();
        yield return lineBreak();
        Vars.theme = macros1.either("\'\'chimie\'\'", "\'\'ingénierie\'\'", "\'\'biologie\'\'");
        yield return lineBreak();
        yield return text(@"Ils observaient la ville depuis les fenêtres de leur manoir. Des hommes en costume d'affaires brun et des femmes aux larges ceintures de tissu nouées autour de la taille s'affairaient sur les trottoirs bondés et dans les voies piétonnes qui serpentaient au travers de cette l'université. Ce qui avait été une région isolée et bucolique était désormais une métropole prospère.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"C'était cette même prospérité qui continuellement tentait la famille. N'étaient-ce pas le génie de leur lignage et les affaires menées avec ingéniosité par leurs ancêtres, qui avaient chassé la maladie du pays ? N'étaient-ce pas leurs parents avisés qui avaient permis de financer une université grâce aux fonds gouvernementaux – ces mêmes parents qui rentrèrent dans cette génération-ci en connaissant le secret de la vie éternelle ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pourtant, les habitants les considéraient comme des étrangers, avec ce jugement silencieux qu'ils réservaient pour leur for intérieur. L'administration de l'université offrait son assistance et partageait des mots d'encouragement, mais aux yeux de la famille, leur présence n'était pas reconnue à sa juste valeur. Chaque jour qui passait, leur ressentiment grandissait. Cette rancœur bouillonnait, préoccupation jamais loin de leurs expérimentations si ambitieuses.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La science ne devait pas être contenue par les limites arbitraires de l'éthique ! La famille savait qu'il s'agissait là de sa chance de légitimer l'héritage de plusieurs générations, de prouver que le génie audacieux, vif et incontestable serait l'instrument du progrès. Les fins justifiaient les moyens. Depuis les ténèbres, une étincelle électrique se formerait et bientôt, elle galvaniserait le monde scientifique tout entier !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "UniMayor", null);
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


    // .............
    // #15: NoUniversityIntro

