    IStoryThread passage16_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Légendes locales");
        }
        yield return lineBreak();
        yield return text(@"Trois générations dédiées à la science, dont les membres travaillaient à leur œuvre ineffable, entourés par des murs de pierre érodés. Trois générations, dont les expériences étaient dissimulées au plus profond des forêts, au bout des chemins cahoteux qui traversent la campagne grisâtre.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"L'indifférence de la famille envers les malades pouvait-elle être responsable de la propagation de l'épidémie qui ravagea la région ? La famille prêta vraisemblablement assistance à une force surnaturelle qui, nous le supposons, s'insinua profondément dans les infrastructures de la petite ville, à tel point que la populace fut dans son entièreté transformée en monstres. Mais aurait-on trouvé et déployé un remède pour renverser cette malédiction ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Percer à jour ce mystère fut un effort considérable, l'histoire de la région étant mal documentée et plutôt oubliée. Le souvenir de ces entrepreneurs excentriques isolés en leur campagne n'était lui non plus pas vivace au sein des cercles aristocratiques, nimbé des brumes du temps – une brume épaisse et lourde, comme celle qui s'accroche à la petite vallée. Mais qu'il s'agisse d'un fait ou d'une fiction, les habitants de ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text(@"s'attachent à ces superstitions et se les transmettent en se les murmurant à l'oreille. La nuit, lorsque des bruits étranges transpercent le brouillard, riches comme pauvres tournent le regard vers les châteaux sinistres qui surplombent le paysage, se demandant quelles étranges machinations ont bien pu s'y tramer.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Mathieu Rivero");
        }
        yield break;
    }


