    IStoryThread passage31_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un retour à la civilité");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Bien que les chemins menant en ville fussent parsemés d'ornières, faisant cahoter et craquer calèches et carrosses, les aristocrates, dont l'âge avançait sûrement, profitaient du matin pour échapper à l'air renfermé de leurs manoirs de pierre, et de ruminer sur la beauté austère et mélancolique du paysage.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Durant ces escapades matinales, ils parvinrent à observer une transformation aussi soudaine qu'étrange en ville. Des journaliers se massaient près de terrains laissés à l'abandon pour y construire de nouvelles fondations. Il ne fallut que quelques semaines pour que ces nouveaux bâtiments aux diverses fonctionnalités, et pour autant très quelconques, soient achevés.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Armés de la curiosité et de la soif de connaissance qui les caractérisaient, les " +
            "cousins ne purent résister à la tentation d\'approfondir le sujet.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage31_Fragment_1);
        using (styleScope("hook", "h00003101"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h00003101", HarloweEnchantCommand.Replace, passage31_Fragment_0));

