    IStoryThread passage47_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Maladie lunaire");
        }
        yield return lineBreak();
        if (Vars.round == 13)
        {
            yield return text("Quelle terrible nuit pour les maudits !");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Dans les journaux des cousins, on pouvait lire des récits concernant des réveils à demi nu dans les jardins, en bordure du domaine, les habits déchirés, du sang sur leurs bottes et aux commissures de leurs lèvres. Des souvenirs rémanents de chasse dans les bois, de proies abattues, hantaient leurs rêves, et pourtant... les remplissaient d'une énergie inextinguible !");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Lorsque le corps éviscéré d'un domestique fut retrouvé empalé sur la grille de fer forgé qui courait le long d'un domaine, les lacérations causées par des griffes et les morsures bestiales racontaient une histoire terrible. Les scientifiques luttèrent contre la distraction, se concentrant sur la tâche en cours.");
            yield return lineBreak();
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage47_Fragment_1);
            using (styleScope("hook", "h00004701"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h00004701", HarloweEnchantCommand.Replace, passage47_Fragment_0));

        }
        if (Vars.round == 14)
        {
            yield return text("Une autre victime dans la maisonnée, cela ne pouvait ralentir la progression de l" +
            "eur travail scientifique. Tant qu\'il y aurait plus important, cela ne pouvait êt" +
            "re plus qu\'une préoccupation mineure. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Leur occupation était macabre et sinistre, chaque instant devant être ponctué de prise de notes, d'incisions chirurgicales ou de synthétisation de liquides luminescents. La perte d'un domestique était malheureuse, non pas pour la vie que cela représentait, mais pour la perte d'efficacité que représentait le recrutement d'une nouvelle personne.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage47_Fragment_3);
            using (styleScope("hook", "h00004703"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h00004703", HarloweEnchantCommand.Replace, passage47_Fragment_2));
        }
        yield return lineBreak();
        yield break;
    }

