            using (styleScope("bold", true))
            {
                yield return text("forgeron");
            }
            yield return text(@". Étant dans un état quelque peu second, son invitation dans sa gentilhommière pour poursuivre les libations me parut fort à propos. Nous entretînmes une conversation des plus délicieuses. Si intrigante, en fait, que je fis de son logement le mien pour cette nuit-là. Quelle générosité ! Je vous épargnerai les détails de notre conversation, à la fois tout à fait respectable, et de peu d'intérêt pour vous.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Nous décidâmes de nous dévêtir, comme il est de bon ton lorsqu'on se prépare au sommeil. Malheureusement, la suite des événements échappe à ma mémoire, mais le forgeron fut fort mécontent de nous retrouver dans cette même nudité le lendemain, dans les bras de l'autre, et entourés d'outil de forge... souillés. La réputation de notre famille en souffrit aux yeux du forgeron, et je me fis la réflexion qu'il serait bon d'éviter de le solliciter à l'avenir.");
        }
        if (Vars.bar1 == 2)
        {
            yield return text("Après une brève excursion au bar local, je me pris à discuter avec la fille du ");
            using (styleScope("bold", true))
            {
                yield return text("forgeron");
            }
            yield return text(@". Bien que je sois incapable de comprendre la raison de mes actions, je me suis, depuis, excusé de mes commentaires appuyés et répétés dépréciant sa nature vertueuse. Ces commentaires résultèrent en une altercation avec un gentilhomme ou deux en ce respectable établissement.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Je décidai de me retirer aux alentours de minuit, afin d'éviter plus de raffut. Mes habits, salis et tachés de sang par la bagarre, furent trouvés le long du chemin boueux menant chez le forgeron. Je n'ai pas de souvenir de la suite, mais on m'aurait vu marquer le chien du forgeron au fer rouge et m'endormir nu comme un ver dans le bain de trempe. La réputation de notre famille en souffrit aux yeux du forgeron, et je me fis la réflexion qu'il serait bon d'éviter de le solliciter à l'avenir.");
        }
        yield return lineBreak();
     

        using (styleScope("setupStyleEvnt", true))
        {

            using (styleScope("bold", true))
            {
                yield return text("MISE EN PLACE SPÉCIALE");
            }
            Vars._SetupImage = "Creepy_Icon";

            yield return lineBreak();
            yield return text("Placez un jeton ");
            yield return text("<sprite=\"Creepy_Icon\" index=0>");
            yield return text(" ");
            yield return text("sur le ");
            using (styleScope("bold", true))
            {
                yield return text("forgeron");
            }
            yield return text(". Lorsqu\'un joueur effectue une action dans ce lieu, il ");
            using (styleScope("bold", true))
            {
                yield return text("gagne 1 ");
                yield return text("<sprite=\"Creepy_Icon\" index=0>");
            }
            yield return text(" ");
            yield return text("pour chaque jeton ");
            yield return text("<sprite=\"Creepy_Icon\" index=0>");
            yield return text(" ");
            yield return text("sur ce lieu.");
            yield return lineBreak();
            yield break;
        }
    }


