        }
        if (Vars.bar2 == 2)
        {
            yield return text(@"Je trouve les accusations quant à ma conduite pour le moins perturbantes. Insinuer que je tienne compagnie à ces personnes de mauvaise réputation, que je reçoive monnaie sonnante et trébuchante pour des activités illicites ! C'est aussi absurde que les autres délits dont on m'a accusé ce soir-là.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Je dois bien admettre quelques frasques, certes, mais il est ridicule de croire que parce que je fus retrouvé dévêtu et couvert de sauce tomate, des traces de rouge à lèvres sur tout mon corps, que je sois coupable d'avoir mangé des grappes entières de tomates cerise et ruiné d'autres stocks de légumes.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Malgré mes objections, j\'ai rapidement remboursé le marchand et acheté son silenc" +
