    IStoryThread passage60_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("\"Premier avril\" - Entrée de journal - 1882");
            if (Vars.panacure == Vars.nameA)
            {
                Vars.tempjournal = Vars.nameB;
            }
            else
            {
                Vars.tempjournal = Vars.nameA;
            }
            yield return text(" ");
            yield return text(Vars.tempjournal);
            yield return text(" ");
            yield return text("junior.");
        }
        yield return lineBreak();
        yield return text(@"Cette matinée d'été commençait bien jusqu'à ce que j'entende un cri provenir du jardin. Mes expérimentations m'ont habitué à ce genre de cri de détresse, mais je décidai qu'il était étrange que cela arrive dès le café du matin, alors que l'on venait de me servir mes crêpes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Après avoir refermé mon peignoir, je sortis du manoir à temps pour assister aux derniers instants d'un domestique dévolu à la taille du jardin. En m'entendant arriver, il se tourna vers moi, puis ses traits s'affaissèrent. Des lambeaux de chair sanguinolente tombèrent en crépitant, pareils à des lardons jetés dans une poêle. Une poignée de secondes plus tard, le bonhomme qui jadis s'occupait de nos haies fut réduit à un tas de mousse rosâtre. La substance responsable de ces atrocités, quelle qu'elle fut, avait frayé son chemin profondément dans le sol, créant un trou dans le décor idyllique du jardin.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je bus une gorgée de café et examinai une fiole de verre qui traînait non loin. E" +
            "lle portait l\'inscription « Élixir vital à utiliser pour la prévention des malad" +
            "ies », et je reconnus instantanément l\'écriture d\'un de mes cousins. Ah, quelle " +
            "plaisanterie !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Malheureusement, un autre servant se tenait à proximité, bouche bée, ayant assist" +
            "é à tout le spectacle. Il serait difficile de remplacer ce travailleur.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage60_Fragment_1);
        using (styleScope("hook", "h00006001"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h00006001", HarloweEnchantCommand.Replace, passage60_Fragment_0));

        yield break;
    }

