        }
        yield return lineBreak();
        yield return text(@"Les présents furent épatés par les folies excentriques présentée ce jour-là. Certains individus de faible constitution furent pris de nausées et d'évanouissements pendant les cours magistraux, clairement éblouis par la portée infinie de ces expériences visionnaires.");
