        yield return link("cliquez ici.", "SymposiumFail", null);
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Si le total est égal ou supérieur à ");
        using (styleScope("bold", true))
        {
            yield return text(Vars.symp);
        }
        yield return text(", ");
        yield return link("cliquez ici.", "SymposiumMiddle", null);
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cependant, si le total est égal ou supérieur à ");
