                yield return lineBreak();
                yield return lineBreak();
                yield return text(@"« Votre famille a contribué à notre Fraternité. Nous sommes là pour rembourser cette dette, en vous offrant nos services, » annonça-t-il, levant sa manche pour révéler un tatouage représentant un arc et une flèche. Sans plus d'explications ni de questions, il se dirigea vers les quartiers des domestiques.");
