    IStoryThread passage84_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une peste inexorable");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Leurs parents avaient beau avoir échappé aux affres de la Fièvre jaune grâce aux bienfaits de l'aristocratie, c'est-à-dire une certaine distance avec la populace, les jeunes scientifiques, eux, furent incapables d'éviter les effets d'un environnement aussi morbide. Les années passant, ils se trouvèrent frappés de maladies chroniques qui resteraient avec eux pour le restant de leur vie. Leur condition hanta leur travail : parfois, ils devaient s'isoler et s'aliter des semaines durant.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Chacun d\'entre eux s\'attela à la confection d\'un remède qui lui était propre, sac" +
            "hant qu\'en cas d\'échec, ");
        using (styleScope("bold", true))
        {
            yield return text("la maladie et ses symptômes seraient transmis à la future génération.");
