    // .............
    // #86: DevastationIntro

    void passage86_Init()
    {
        this.Passages[@"DevastationIntro"] = new StoryPassage(@"DevastationIntro", new string[] { "INTRO", "revised", "rev2", "TRADUIT", }, passage86_Main);
    }

    IStoryThread passage86_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION II :");
            yield return lineBreak();
            yield return text("L\'épidémie frappe");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"À peine l'âpre hiver de 1862 terminé, une deuxième épidémie s'abattit sur la ville avec une virulence cruelle. Cette fois, cependant, la ville ne put se relever. Des bâtiments furent laissés à l'abandon des moisissures, et les malades se réfugièrent dans la campagne. Certains partirent dans des camps à proximité de Bucarest, tandis que des âmes moins fortunées perdirent la vie sur les sentiers glacés, leur chair ne devant réapparaître sur les routes boueuses qu'avec le dégel printanier. Sans aide, la ville était perdue et impuissante ; elle déclina jusqu'à n'être plus que l'ombre d'elle-même.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La famille revint et assista à une désolation dont aucun de ses membres n'avait, durant sa courte existence, été témoin. Les joies d'un mariage récent furent vite éclipsées par la réalité de la maladie. Les citadins qui avaient, par entêtement, refusé de rejoindre l'exode de masse brûlaient de l'encens dans leur foyer pour limiter la transmission miasmatique de la fièvre. Cette pratique fut instantanément adoptée dans les domaines familiaux. Des années durant, chaque nuit on entendrait les encensoirs tintinnabuler dans la vallée endeuillée afin de repousser la maladie, et ce bien que le cimetière soit submergé de nouveaux corps.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cet environnement solitaire et lugubre testerait les limites de la santé mentale de la plupart des hommes. Mais pour les scientifiques, cette époque était propice à une productivité hors normes. Peut-être était-ce l'envie de se racheter qui les poussait à travailler, ou alors était-ce la pensée obsédante qu'eux aussi, ils étaient mortels. Quoi qu'il en soit, ils s'étaient jetés à corps perdu dans leurs études, confiants que, de par son passage par cette tragédie, l'héritage de leur père trouverait enfin sa place pour toujours dans les annales de la science !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"On commença à remarquer leurs activités, mais pas de la façon académique dont les scientifiques l'imaginaient. Des ombres aux intentions mystérieuses surveillaient la région. Ignorant tout des sinistres machinations qui se tramaient, les scientifiques se consacraient pleinement à leur ouvrage. Ils se retrouveraient très bientôt confrontés à un choix qui ébranlerait les fondations de la pensée scientifique de leur temps... mais aussi celles de leur raison.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Continuer...", "DiseaseConsequence", null);
        yield return lineBreak();
        Vars.letter = macros1.a(1, 2, 3, 4, 5);
        Vars.letter = macros1.shuffled((HarloweSpread)Vars.letter);
        Vars.letterA = Vars.letter["1st"];
        Vars.letterB = Vars.letter["2nd"];
        Vars.letterC = Vars.letter["3rd"];
        Vars.letA = 0;
        Vars.letB = 0;
        Vars.letC = 0;
        Vars.goodcount = 0;
