    IStoryThread passage103_Fragment_1()
    {
        using (styleScope("bold", true))
        {
            yield return text("Au sujet d\'un certain rendez-vous secret - Lettre - ");
            yield return text(macros1.either("Avril", "Août", "Octobre"));
            yield return text(" ");
            yield return text(macros1.random(1, 29));
            yield return text(", 1865");
        }
        yield return lineBreak();
        yield return text(Vars.meet);
        yield return text(", je vous écris cette lettre pour faire suite à ma rencontre avec un associé de l" +
            "a Société Internationale de Saint Hubertus. Notre conversation fut brève, mais f" +
            "ort enrichissante – de quoi piquer ma curiosité.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il me fut révélé que vos intentions sont ");
        if (Vars.wolves == "malfaisante")
        {
            yield return text(@"malfaisantes. Cet abominable Ordre est consumée par l'avarice, et essaie de déterrer les secrets antiques enfouis dans cette région du monde, afin de les utiliser pour changer l'humanité. Son désir le plus ardent n'est que de répandre un fléau de monstruosités sur le monde. Vous avez seulement demandé que votre travail soit gardé ");
            using (styleScope("bold", true))
            {
                yield return text("dissimulé");
            }
            yield return text(".");
        }
        else if (Vars.wolves == "bienfaisante")
        {
            yield return text(@"incontestablement bonnes. La Société n'a d'autre préoccupation que l'établissement de refuges pour ceux qui seraient frappés par la maladie. Votre représentante a même révélé avoir une anormalité physique qui lui allonge les canines en crocs acérés. Elle est partie promptement avant que le crépuscule ne tombe, ignorant mes suppliques, mais elle me recommanda d'investiguer sur les secrets qui se révéleraient bientôt.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Étant intimement accointé avec les affaires occultes, cette dernière affirmation " +
            "me semble surprenante. Mes seules réserves proviennent de vos actions, et de com" +
            "ment elles aideront ou ralentiront ma progression dans mes recherches scientifiq" +
            "ues.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("C\'est avec sincérité que :");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("...j\'ai décidé de ");
        using (styleScope("hook", "h00035"))
            yield return link("jurer allégeance et de me rallier à votre cause.", null, () => enchantHook("h00035", HarloweEnchantCommand.Replace, passage103_Fragment_0));
        yield return lineBreak();
        yield return lineBreak();
        yield return text("... j\'ai décidé de ");
        yield return link("refuser cette offre ridicule.", "RefusalWolves", null);
        yield break;
    }

