    IStoryThread passage104_Main()
    {
        Vars.disease1 = macros1.either(1, 2);
        if (Vars.disease1 == 1)
        {
            using (styleScope("bold", true))
            {
                yield return text("Une année de maladie");
            }
            yield return lineBreak();
            yield return text("Même les esprits les plus affûtés ne peuvent échapper à la fragilité du corps. La" +
            " peste qui s\'abattait sur la maisonnée draina l\'énergie nécessaire au travail de" +
            "s scientifiques et les laissa alités pendant des mois durant. ");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage104_Fragment_1);
            using (styleScope("hook", "h000010401"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000010401", HarloweEnchantCommand.Replace, passage104_Fragment_0));

        }
        if (Vars.disease1 == 2)
        {
            using (styleScope("bold", true))
            {
                yield return text("Du temps et du repos");
            }
            yield return lineBreak();
            yield return text(@"Il semblait que les cousins furent fortunés, lors de leurs jeunes années. Même les esprits les plus affûtés ne peuvent échapper à la fragilité du corps. Mais, grâce à une hygiène de vie impeccable dont les mamelles étaient repos, régime draconien et saignées régulières, ces déficiences purent être nullifiées, ou presque.");
            yield return lineBreak();
            yield return lineBreak();
