            yield return text(@", de façon amusante, vouées à l'exploitation de votre prochain. La Fraternité espère utiliser la récente épidémie pour couvrir leurs activité dans la région. Ses membres espèrent déterrer d'anciens secrets surnaturels afin de les utiliser pour gagner pouvoir politique et fortune pécuniaire. Bien que je reste sceptique, si ces travaux sont couronnés de succès, j'entretiendrai un vif intérêt pour leur résultat... Vous avez simplement demandé que votre travail demeure ");
            using (styleScope("bold", true))
            {
                yield return text("dissimulé");
            }
            yield return text(".");
        }
        else if (Vars.hunters == "bienfaisante")
        {
            yield return text(@"bonnes. Noter l'étrange silence de la ville ces dernières années a été une bonne idée de votre part. La Fraternité, elle, a gardé un œil vigilant sur le cours des événements. Elle semble seulement se préoccuper de découvrir et éliminer quiconque est derrière ce secret. Vous m'avez demandé d'investiguer sur les les secrets qui se révéleraient bientôt.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Moi aussi, j\'ai l\'esprit entrepreneur, en quelque sorte. Vos buts ne sont pas si " +
            "différents des miens. Mes seules réserves proviennent de vos actions, et de comm" +
            "ent elles aideront ou ralentiront ma progression dans mes recherches scientifiqu" +
            "es.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("C\'est avec sincérité que :");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("...j\'ai décidé de ");
        using (styleScope("hook", "h00039"))
            yield return link("jurer allégeance et de me rallier à votre cause.", null, () => enchantHook("h00039", HarloweEnchantCommand.Replace, passage109_Fragment_0));
        yield return lineBreak();
        yield return lineBreak();
        yield return text("... j\'ai décidé de ");
        yield return link("refuser cette offre ridicule.", "RefusalHunters", null);
        yield break;
    }

