    IStoryThread passage112_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Ne permettez pas aux autres joueurs de voir le livret Histoire lorsque vous prene" +
            "z la décision ci-dessous.");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Poursuivre l\'investigation - Entrées compilées du journal de ");
            yield return text(Vars.nameA);
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.inv == Vars.ba)
        {
            yield return text("J\'arrivai à ma destination, l\'étrange ");
            yield return text(Vars.ba);
            yield return text(", sous le couvert de la nuit. Les missions de discrétion comme celle-ci n\'étaient" +
            " pas mon fort, mais je gardai le col de mon long manteau bien relevé afin de dis" +
            "simuler mon identité au mieux, fussé-je découvert.");
        }
        if (Vars.inv == Vars.bb)
        {
            yield return text("Un épais brouillard dissimula mon approche, la nuit où je décidai de mener l\'enqu" +
            "ête sur l\'étrange ");
            yield return text(Vars.bb);
            yield return text(". Je demandai à mon chauffeur d\'attendre mon retour à la limite de la ville avant" +
            " de me faufiler dans les rues vides. Personne ne sortirait ce soir-là, et bientô" +
            "t, j\'avais pénétré dans le bâtiment sans élever aucun soupçon.");
        }
        if (Vars.inv == Vars.bc)
        {
            yield return text("À mon grand regret, un");
            yield return text(macros1.either("gentilhomme", "e gente dame"));
            yield return text(@"se tenait au seuil de l'établissement. À une heure si tardive, j'en déduisis qu'on montait donc la garde. Mes plans ne sauraient être contrecarrés si facilement ! J'inclinai mon chapeau afin de dissimuler mon visage et me faufilai dans une allée. Le verrou de la porte de service ne fut qu'une formalité, et j'entrai sans un bruit.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je pouvais à présent récupérer et produire des preuves aidant à ");
        using (styleScope("bold", true))
        {
            yield return text("révéler");
        }
        yield return text(" ");
        yield return text("ce qui se tramait dans l\'enceinte de ce bâtiment, ou ");
        using (styleScope("bold", true))
        {
            yield return text("dissimuler");
        }
        yield return text(" ");
        yield return text("la vérité et permettre aux activités s\'y produisant de se perpétuer. ");
        using (styleScope("bold", true))
        {
            yield return text("La décision était toute prise :");
        }
        yield return lineBreak();
        yield return lineBreak();
        Vars.playA = int.Parse(Vars.playA) + 1;
        using (styleScope("hook", "h00045"))
