        yield return lineBreak();
        using (styleScope("hook", "h00046"))
            yield return link("J\'ai dissimulé le vrai but du bâtiment.", null, () => enchantHook("h00046", HarloweEnchantCommand.Replace, passage112_Fragment_1));
        yield return lineBreak();
        yield break;
    }

