    void passage119_Init()
    {
        this.Passages[@"MostInvestigated"] = new StoryPassage(@"MostInvestigated", new string[] { }, passage119_Main);
    }

    IStoryThread passage119_Main()
    {
        if (Vars.playA > macros1.max(Vars.playB, Vars.playC, Vars.playD, Vars.playE))
        {
            Vars.most = Vars.nameA;
        }
        else if (Vars.playB > macros1.max(Vars.playC, Vars.playD, Vars.playE))
        {
            Vars.most = Vars.nameB;
        }
        else if (Vars.playC > macros1.max(Vars.playD, Vars.playE))
        {
            Vars.most = Vars.nameC;
        }
        else if (Vars.playD > macros1.max(Vars.playE))
        {
            Vars.most = Vars.nameD;
        }
        else
        {
            Vars.most = Vars.nameE;
        }
        if (Vars.hunters == "malfaisante")
        {
            if (Vars.goodcount < 2)
            {
                Vars.society = "Fraternité des Chasseurs";
            }
            else
            {
                Vars.society = "Société de Saint Hubertus";
            }
        }
        if (Vars.hunters == "bienfaisante")
        {
            if (Vars.goodcount > 1)
            {
                Vars.society = "Fraternité des Chasseurs";
            }
            else
            {
                Vars.society = "Société de Saint Hubertus";
            }
        }
        if (Vars.most == 0 || Vars.most == "")
        {
            yield return abort(goToPassage: "DiseaseEnd");
        }
        else
        {
            using (styleScope("bold", true))
            {
                yield return text("La majorité des investigations...");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(Vars.most);
            yield return text(" ");
            yield return text("conduisit la plupart des investigations. Cela, la ");
            yield return text(Vars.society);
            yield return text(" ");
            yield return text("le remarqua et, en dépit des allégeances et affinités de chacun, un tel esprit d\'" +
            "exploration semblait digne de récompense.");
            yield return lineBreak();
            yield return lineBreak();
            using (styleScope("bold", true))
            {
                yield return text(Vars.most);
                yield return text(" ");
                yield return text("gagne immédiatement 4 PV.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez ici pour continuer...", "DiseaseEnd", null);
        yield return lineBreak();
        yield break;
    }


