    IStoryThread passage124_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Donnez précautionneusement le livret Histoire à ");
            yield return text(Vars.charity);
            yield return text(". Ce choix est lu à haute voix et est fait de façon publique.");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("\"Intérêt universel\" - Entrée de journal - Novembre 1859 - ");
            yield return text(Vars.charity);
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il y a trois jours, j'ai reçu une lettre du gouvernement hongrois et il y a deux jours, mes cousins se sont dit qu'il serait de bon ton de se moquer de moi. Cette horrible communauté était chère aux yeux de mes parents ; un sentiment que ces mécréants ne connaissent pas !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je ne suis pas du genre à me morfondre, à l\'attente d\'une confirmation des univer" +
            "sités européennes, et leurs doyens replets et complaisants. Mais avoir l\'opportu" +
            "nité de ");
        using (styleScope("bold", true))
        {
            yield return text("choisir le sujet du prochain Colloque");
        }
        yield return text(", cela pourrait peut-être être la raison de l\'édification d\'une ");
        using (styleScope("bold", true))
        {
            yield return text("université");
        }
        yield return text(" ");
        yield return text("à ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text("?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mes parents avaient instillé en moi une ardeur scientifique qui dépasse même celle des membres de ma famille, pour qui j'ai tout de même une certaine affection. Lorsque je revins de mes études à l'étranger, ce furent mes aptitudes qui poussèrent mes cousins à l'action. Qu'ils soient maudits, eux et leurs moqueries ! Je leur montrerai de quel bois je me chauffe. À vrai dire, j'ai déjà rédigé ma réponse. Rira bien qui rira le dernier.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Choisissez à quelle science notre famille se consacrera pendant cette Génération " +
            ":");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00060"))
            yield return link("La chimie.", null, () => enchantHook("h00060", HarloweEnchantCommand.Replace, passage124_Fragment_0));
        yield return lineBreak();
        yield return lineBreak();
