        {
            yield return text("La ");
            yield return text(macros1.either("Terrifiante", "Transcendentale", "Monumentale", "Maléfique", "Cauchemardesque", "Légendaire", "Noble", "Phénoménale", "Fabuleuse", "Géniale", "Vile"));
