    // #136: NewMaster

    void passage136_Init()
    {
        this.Passages[@"NewMaster"] = new StoryPassage(@"NewMaster", new string[] { }, passage136_Main);
    }

    IStoryThread passage136_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Maître de son propre destin");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il semblait que la morosité qui régnait sur ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text(@"avait contaminé les grand-salles des domaines. En effet, les cousins, lorsqu'ils eurent exploré tous les recoins de leur demeure, découvrirent d'immenses laboratoires souterrains abandonnés en grande hâte. Des verres mesureurs étaient brisés au sol, leurs fragments étincelant au beau milieu des restes d'appareils rouillés. Et, plus étrange encore, les restes d'une expérience exceptionnelle. Oh, quelle folie peut s'emparer d'un vieil esprit abattu !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pour d'aucuns d'imagination inférieure, cela aurait pu sonner la fin des ambitions, mais les esprits exubérants et juvéniles ne sauraient être contraints par les caprices de leurs progéniteurs ! Si leurs devanciers n'avaient pu poursuivre le dur labeur entrepris des générations plus tôt, les cousins créeraient leur propre héritage !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour créer un nouveau Grand Œuvre !", "NewMaster1A", null);
        yield return lineBreak();
        yield break;
    }


