    // #155: MWCompleteHubC

    void passage155_Init()
    {
        this.Passages[@"MWCompleteHubC"] = new StoryPassage(@"MWCompleteHubC", new string[] { }, passage155_Main);
    }

    IStoryThread passage155_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text(macros1.either("Le grand œuvre est réalisé", "J\'ai fait l\'impossible !", "Mon héritage est assuré", "AH HA HA HAAAAA !!!", "Ma glorieuse création", "La gloire est mienne pour l\'éternité !"));
            yield return text(" ");
            yield return text("- ");
            yield return text(Vars.nameC);
            yield return text(" ");
            yield return text("- Extrait d\'une entrée de journal");
        }
        yield return lineBreak();
        if (Vars.typeC == "creature")
        {
            yield return text("Sur le coup de minuit, la foudre s\'abattit sur le paratonnerre, envoyant un formi" +
            "dable courant électrique dans l\'appareil. Ma créature se réveilla et, les yeux é" +
            "carquillés, elle me contempla, moi qui l\'avais créée ! Je l\'avais fait. J\'avais " +
            "créé la vie !");
        }
        if (Vars.typeC == "power")
        {
            yield return text("Voir mon labeur payer, voir la ");
            yield return text(Vars.creationC);
            yield return text("enfin se concrétiser ; la passion du moment submergea mes sens. Je l\'avais fait. " +
            "J\'avais montré le poing à Dieu, et à tous ceux qui doutaient de moi ! Vous aviez" +
            " tort... Je suis invincible !");
        }
        if (Vars.typeC == "robot")
        {
            yield return text("Un bref éclat de lumière, et le travail fut fait. Je jetai mes lunettes de sécuri" +
            "té au sol pour mieux admirer ma création de mes propres yeux - la ");
            yield return text(Vars.creationC);
            yield return text(". Le métal poli bourdonnait sous l\'impulsion des mécanismes qu\'il renfermait... e" +
            "t soudain, l\'appareil se mit en mouvement ! Ô glorieux automate, avec toi à mes " +
            "côtés, le monde scientifique s\'agenouillera devant moi !");
        }
        if (Vars.typeC == "weapon")
        {
            yield return text(@"Je m'emparai de la poignée et pressai la gâchette de métal poli. Je dus attendre que la poussière retombe pour constater les dégâts : le mur de mon laboratoire s'était éboulé sous la force de l'impact. Je ne pus contenir un sourire des plus sinistres. Le monde se souviendrait de ce jour, et de l'arme que j'avais créée. Mon nom serait éternellement célèbre.");
        }
        if (Vars.typeC == "medicine")
        {
            yield return text("Je tapotai la fiole, contemplant les tourbillons formés par le liquide luminescen" +
            "t, si pur. Quel succès ! Lorsque l\'on pourrait produire la ");
            yield return text(Vars.creationC);
            yield return text("en masse, l\'héritage de ma famille serait assuré. J\'éclatai de rire. Encore et en" +
            "core. À gorge déployée. Mon rire devait, des années plus tard, rebondir contre l" +
            "es voûtes de pierre de mon domaine.");
        }
        if (Vars.typeC == "drug")
        {
            yield return text("J\'observai les effets lorsque la seringue remplie de ");
            yield return text(Vars.creationC);
            yield return text(@"se vida dans le sujet de test peu consentant. Comme prévu, la réponse fut immédiate et virulente. Pendant tant d'années, j'avais trimé dans la solitude de mon domaine et, désormais, ma création était achevée ! L'émotion emplit mes yeux d'une humidité que j'essuyai vite.");
        }
        if (Vars.typeC == "demon")
        {
            yield return text("Le monde s\'obscurcit autour de moi. La ");
            yield return text(Vars.creationC);
            yield return text(@"émergea d'une déchirure dans le temps et l'espace. Je sentais le pouvoir immense de cet être insidieux, l'air chauffer et vibrer de sa seule présence. L'être se tourna vers moi et, d'un rugissement, me prêta allégeance : « Maître. » Je l'avais fait ! J'étais désormais aux commandes, et le monde regretterait le jour où il avait osé douter de ");
            yield return text(Vars.nameC);
            yield return text("troisième du nom !");
        }
        if (Vars.typeC == "ritual")
        {
            yield return text("Les préparatifs furent pénibles, mais l\'énergie dégagée par le rituel me laissa b" +
            "ouche bée, sidéré par ma propre création. La ");
            yield return text(Vars.creationC);
            yield return text("était un succès ! Et les pouvoirs auxquels j\'avais désormais accès étaient indici" +
            "bles !");
        }
        yield break;
    }


