    IStoryThread passage160_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Le remède");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les fins de semaine, ils dînaient ensemble, acceptant d'accueillir les uns les autres à tour de rôle sans faire d'histoire. De nombreuses conversations dérivaient sur les sujets bouillants du moment. Aucun sujet n'était aussi fréquent que la maladie. Pour être plus précis, la Fièvre jaune, les quintes de toux et les glas qui inlassablement l'avaient accompagnée à chaque souffle de vent.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le ");
        if (Vars.players == 2)
        {
            yield return text("duo");
        }
        if (Vars.players == 3)
        {
            yield return text("trio");
        }
        if (Vars.players == 4)
        {
            yield return text("quatuor");
        }
        if (Vars.players == 5)
        {
            yield return text("quintet");
        }
        yield return text(" ");
        yield return text(@"de scientifiques respectables à la réputation établie (et mauvaise, soit dit en passant) tomba d'accord : si ce problème était trivial, c'était la conception du remède qui causait bien des maux de tête. La maladie leur donnait une très bonne opportunité de cacher leur entreprise douteuse. S'ils devaient verser dans la philanthropie, la nature secrète de leurs expériences en souffrirait.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ils décidèrent de laisser ce souci à la discrétion de chacun. Si quelqu\'un se sen" +
            "tait d\'humeur industrieuse, il n\'avait qu\'à le faire, voilà tout.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage160_Fragment_1);
        using (styleScope("hook", "h000016001"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000016001", HarloweEnchantCommand.Replace, passage160_Fragment_0));

        yield return lineBreak();
        yield break;
    }

