    IStoryThread passage164_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Échapper à la malédiction");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Dans les vieilles années des cousins, la ville rejeta la science et leurs collègues, méfiants, s'éloignèrent d'eux. Le poids de ces injustices était trop insupportable. Levant le poing et maudissant les dieux, ils mirent fin à leur génération baignant dans le désespoir !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les archives de cette époque ne mentionnent aucune note de collaboration entre eux. Et pourtant, chacun des individus, dans la solitude de son laboratoire, s'adonna à un accès de rage destructeur. Les cousins détruisirent leur équipement : béchers et fioles, anomalies biologiques baignant dans le formol, appareils étranges constellés de taches de rouille, tout finit au sol, en morceaux : la catharsis apportée par le chaos primait.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ils tinrent entre leur mains le plan inepte passé de génération en génération, qu" +
            "i les minait, avec ses ambitions scientifiques inatteignables... et, bientôt, il" +
            " plut sur le sol du laboratoire une pluie de lambeaux de papier.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Enfin, ils étaient libérés de cet héritage maudit !");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage164_Fragment_1);
        using (styleScope("hook", "h000016401"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000016401", HarloweEnchantCommand.Replace, passage164_Fragment_0));

        yield break;
