            yield return text(".)");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("OU");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00146"))
            yield return link("A un accident malheureux.", null, () => enchantHook("h00146", HarloweEnchantCommand.Replace, passage168_Fragment_1));
        yield return text(" ");
