    IStoryThread passage170_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Les conséquences de la désobéissance");
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.society == "Fraternité des Chasseurs ")
        {
            yield return text(@"Les soirs, la Fraternité se rassemblait dans l'ancienne mairie et célébrait la prise de contrôle de la petite bourgade. On entendait les vivats et les festivités jusque tard dans la nuit dans les rues avoisinantes. Les citadins n'avaient aucune raison de douter de leur loyauté, puisqu'il apparaissait que les activités de la Fraternité avaient éloigné d'eux la maladie et les superstitions.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Pour les membres de la famille qui les avaient assistés, ils affichaient des sourires rayonnants mais fallacieux, levaient des toasts à leur partenariat, si pérenne. Mais à l'encontre de ceux qui avaient comploté contre eux, ils demeuraient toujours méfiants.");
        }
        if (Vars.society == "Société de Saint Hubert")
        {
            yield return text(@"En plein centre-ville et en pleine journée, la tête haute et sans peur d'en souffrir les conséquences, se promenait une bête à la fourrure argentée. Presque humaine, dressée sur ses pattes arrière, elle se dirigea vers l'ancienne mairie. Arrivée sur son parvis, elle leva le cœur encore battant d'un homme qui avait refusé de rejoindre leurs rangs. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"La Société n'avait pas hésité à se montrer sous son vrai jour, à prendre le contrôle de la ville et à proposer des alliances aux termes léonins. Les vitrines et les fenêtres des foyers étaient maculées de sang et de tripes. Leur colère épargna la famille : leur avait-elle porté allégeance, ou la Société avait-elle simplement identifié et contrôlé le labeur entrepris par la famille ?");
        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.society == "Fraternité des Chasseurs ")
        {
            //yield return enchantIntoLink("Cliquez pour continuer...", passage170_Fragment_1);
            using (styleScope("hook", "h000017001"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000017001", HarloweEnchantCommand.Replace, passage170_Fragment_0));

        }
        if (Vars.society == "Société de Saint Hubert")
        {
            //yield return enchantIntoLink("Cliquez pour continuer...", passage170_Fragment_3);
            using (styleScope("hook", "h000017003"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000017003", HarloweEnchantCommand.Replace, passage170_Fragment_2));

        }
        yield return lineBreak();
        yield return lineBreak();
        //yield return link("Cliquez pour continuer...", "EvilMayor", null);
        yield return lineBreak();
        yield break;
    }

