    IStoryThread passage179_Fragment_0()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un arrangement louche");
        }
        yield return lineBreak();
        if (Vars.hunters == "malfaisante")
        {
            yield return text("Il était peu courant pour ");
            yield return text(Vars.gen1creep);
            yield return text(", ou pour quiconque de cette lignée solitaire, de recevoir des visiteurs inconnus" +
            ", mais quelque chose piqua sa curiosité. Une conversation lors d\'un dîner était " +
            "consignée dans une entrée de journal :");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"« Votre domaine est tout simplement exquis, commenta le représentant avec un sourire déconcertant. Je suis impressionné de trouver un diamant brut, serti dans cet endroit si reculé. Mais, vous en conviendrez, cette gemme a besoin d'être taillée pour mieux briller et je voudrais vous offrir les outils permettant cela. »");
            yield return text("Il était noté que les maniérismes de cet individu relevaient à la fois du mystère" +
            " et du complot.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Le représentant de la Fraternité des Chasseurs offrit son aide, ainsi que des fon" +
            "ds substantiels. Avec « l\'espoir » que cette aide soit récompensée à l\'avenir.");
            yield return lineBreak();
            yield return lineBreak();
            using (styleScope("bold", true))
            {
                yield return text("FAITES UN CHOIX :");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return link("Acceptez l\'offre.", "Gen1CreepyYes", null);
            yield return text("(Gagnez alors 2 $.)");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("OU");
            yield return lineBreak();
            yield return lineBreak();
            yield return link("Refusez l\'offre.", "Gen1CreepyNo", null);
            yield return text("(Évitez une dette future.)");
            yield return lineBreak();
            yield return lineBreak();
        }
        if (Vars.wolves == "malfaisante")
        {
            yield return text("Il était peu courant pour ");
            yield return text(Vars.gen1creep);
            yield return text(", ou pour quiconque de cette lignée solitaire, de recevoir des visiteurs inconnus" +
            ", mais quelque chose piqua sa curiosité. Une conversation lors d\'un dîner était " +
            "consignée dans une entrée de journal :");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"« Votre réputation dans toute la région vous tient pour anticonformiste, expliqua le représentant de la Société de Saint Hubertus avec, comme l'indiquait le journal, un sourire éclatant. Il se pencha avec un air conspirateur, et une bouffée de parfum parvint à son vis-à-vis, si lourde et capiteuse qu'elle lui mit les larmes aux yeux. Si j'en crois les racontars, vous ne voulez pas vous plier aux règles académiques afin de ne pas brider l'excellence de votre travail. Veuillez, je vous en prie, me permettre d'admirer vos expérimentations. »");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Ceci était audacieux, à la limite de l\'indécence... Que cet homme était osé ! Le " +
            "choix fut laissé d\'expérimenter une fois de plus. Cela valait-il le risque de, p" +
            "eut-être, trop en révéler sur l\'ouvrage familial ?");
            yield return lineBreak();
            yield return lineBreak();
            using (styleScope("bold", true))
            {
                yield return text("FAITES UN CHOIX :");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return link("Accepter.", "Gen1CreepyYes", null);
            yield return text("(Effectuez l\'action Expérimenter.)");
            yield return lineBreak();
            yield return text("OU");
            yield return lineBreak();
            yield return link("Refuser.", "Gen1CreepyNo", null);
            yield return text("(Vous ne pouvez pas ou ne souhaitez pas effectuer cette action.)");
            yield return lineBreak();
        }
        yield return lineBreak();
        yield break;
    }

