    IStoryThread passage183_Fragment_3()
    {
        yield return text("« Vous faites bien de faire preuve de précaution, affirma le garçon d\'écurie. La " +
            "situation, telle que je la comprends, est très simple. La Société de Saint Huber" +
            "tus est ");
        yield return text(Vars.wolves);
        yield return text(". La Fraternité des Chasseurs est ");
        yield return text(Vars.hunters);
        yield return text(". Cela ne va pas plus loin que ça, pour moi, en tout cas. »");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.wolves == "bienfaisante")
        {
            yield return text("\"La Société veut faire du village un refuge pour toutes sortes de parias. Ses mem" +
            "bres veulent ");
            using (styleScope("bold", true))
            {
                yield return text("révéler");
            }
            yield return text("les actes malfaisants qui se trament dans la région et s\'ils le font, vous pouvez" +
            " être certains qu\'ils construiront une université qui formera des ");
            using (styleScope("bold", true))
            {
                yield return text("employés qualifiés");
            }
            yield return text(".");
        }
        if (Vars.wolves == "malfaisante")
        {
            yield return text("\"La Société... je ne sais pas vraiment ce que veulent ses membres, au fond. J\'ai " +
            "l\'impression qu\'ils souhaitent se venger de l\'humanité. Ce n\'est pas très spécif" +
            "ique, mais je crois qu\'ils souhaitent garder leur œuvre ");
            using (styleScope("bold", true))
            {
                yield return text("dissimulé");
            }
            yield return text("et, alors que nous parlons, mettent en place des infrastructures leur permettant " +
            "d");
            using (styleScope("bold", true))
            {
                yield return text("\'Expérimenter");
            }
            yield return text(".");
        }
        if (Vars.hunters == "bienfaisante")
        {
            yield return text("\"Ah, la Fraternité... la routine des bienfaisants. ");
            using (styleScope("bold", true))
            {
                yield return text("Révéler");
            }
            yield return text("les injustices commises dans le village aujourd\'hui, et, demain, pourchasser les " +
            "démons qui rôdent en la campagne. Si vous voulez que ce monde fou ");
            using (styleScope("bold", true))
            {
                yield return text("redevienne sain d\'esprit");
            }
            yield return text("ce sont ceux que vous devez aider.");
        }
        if (Vars.hunters == "malfaisante")
        {
            yield return text("« ");
            using (styleScope("bold", true))
            {
                yield return text("L\'argent");
            }
            yield return text(", le pouvoir, l\'influence. Si la Fraternité peut utiliser ces sombres secrets à l" +
            "eur avantage, elle le fera. Ses membres veulent ");
            using (styleScope("bold", true))
            {
                yield return text("dissimuler");
            }
            yield return text("leur travail dans le village, et, pour cela, n\'hésiteront pas à faire des crédule" +
            "s et des individus de faible volonté leurs proies.");
        }
        yield return text(" ");
        yield return text("Il ponctua sa tirade d\'un nuage chargé de tabac âcre.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(Vars.meet);
        yield return text(" ");
        yield return text(@"fut fasciné par l'idée qu'il n'y ait non pas une, mais deux sociétés secrètes nichées dans le village. Le garçon d'écurie, après une petite transaction pécuniaire, fut même disposé à lui donner des instructions pour contacter chacune des factions afin que ");
        yield return text(Vars.meet);
        yield return text(" ");
        yield return text("rejoigne leurs rangs. Quel curieux dilemme il fallait résoudre aujourd\'hui !");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Vous pouvez choisir de :");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00157"))
            yield return link("Rejoindre la Société de Saint Hubertus.", null, () => enchantHook("h00157", HarloweEnchantCommand.Replace, passage183_Fragment_0));
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00158"))
            yield return link("Rejoindre la Fraternité des Chasseurs.", null, () => enchantHook("h00158", HarloweEnchantCommand.Replace, passage183_Fragment_1));
        yield return lineBreak();
        yield return lineBreak();
        yield return text("OU");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00159"))
            yield return link("Partir et ne rien faire.", null, () => enchantHook("h00159", HarloweEnchantCommand.Replace, passage183_Fragment_2));
        yield return lineBreak();
        yield break;
    }

