        yield return lineBreak();
        yield return text("Tous les joueurs se munissent de leur jeton Vote et le placent dans leur main. Le" +
            "s joueurs choisiront secrètement un côté et ferment le poing. Lorsqu\'ils sont pr" +
            "êts, ils avancent la main au centre de la table.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Un ");
        using (styleScope("bold", true))
        {
            yield return text("Oui");
        }
        yield return text(" ");
        yield return text("indique que le votant souhaite ");
