        yield return text(" ");
        yield return text("quant à leurs exploits de chasse aux monstres.");
        yield return lineBreak();
        yield return text("Un ");
        using (styleScope("bold", true))
        {
            yield return text("Non");
        }
        yield return text(" ");
        yield return text("indique que le votant ");
        using (styleScope("bold", true))
        {
            yield return text("accepte leur histoire");
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Lorsque tous les joueurs ont fait leurs choix, ils révèlent leur vote simultanéme" +
            "nt. Comptabilisez tous les votes. Le côté avec le plus de votes gagne. ");
        using (styleScope("italic", true))
        {
            yield return text("En cas d\'égalité, le dernier joueur ayant joué son tour tranche.");
        }
        yield return lineBreak();
        yield return lineBreak();
        //yield return link("Cliquez ici pour procéder au vote...", "EvilHunter1Event2", null);
