    // .............
    // #187: WolvesEvil1

    void passage187_Init()
    {
        this.Passages[@"WolvesEvil1"] = new StoryPassage(@"WolvesEvil1", new string[] { }, passage187_Main);
    }

    IStoryThread passage187_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Appel à l\'aide");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les récits relatés par les cousins semblent dessiner la même histoire lors de l'été de 1892. Un messager, dont le but était évidemment d'intimider, arriva sans s'annoncer en calèche sur le coup de midi, dans une mise impeccable, si l'on excepte la constellation de gouttelettes de sang séché sur son costume gris. Ses babines étaient trempées de sang, lui faisant comme un horrible masque dégoulinant, et son ventre était rebondi de son récent repas, non loin de lui faire craquer les boutonnières.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"« Je suis venu collecter la dette, dit-il avec une courbette, se nettoyant les dents d'un coup de langue. Vous et votre famille continuez à vivre par nos grâces. Nous avons besoin de l'expertise expérimentale dont vous disposez. Si ceci ne peut être arrangé, conclut-il en désignant un domestique, j'ai déjà apaisé ma faim sur des individus de moindre stature, je vous le garantis, et ce, pas plus tard qu'aujourd'hui... »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Faire un pacte avec des démons ? Il était impossible, pour les jeunes scientifiqu" +
            "es, de croire pleinement en cette offre, et pourtant, laisser un être humain aux" +
            " griffes de ces animaux grotesques, cela semblait relever de l\'inconscience.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("FAITES UN CHOIX :");
        }
        yield return lineBreak();
        yield return text("Dans l\'ordre du tour, chaque joueur décide de donner une Expérience. Les expérien" +
            "ces données sont retournées face cachée et placées sous votre carte Grand Œuvre." +
            "");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Si un joueur effectue une donation, il gagnera un bonus immédiat en fonction du n" +
            "iveau de l\'expérience donnée (");
        using (styleScope("italic", true))
        {
            yield return text("un niveau plus élevé donne une récompense plus élevée");
        }
        yield return text(").");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Si un joueur choisit de ne pas effectuer de donation, ");
        using (styleScope("bold", true))
        {
            yield return text("il perdra un Domestique");
        }
        yield return text(" ");
        yield return text("et ");
        using (styleScope("bold", true))
        {
            yield return text("gagnera 1 ");
            yield return text("<sprite=\"Creepy_Icon\" index=0>");
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez ici pour recevoir vos bonus et vos pénalités...", "TieredRewards1", null);
        yield return lineBreak();
        yield break;
    }


