    IStoryThread passage190_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La Chasse commence");
        }
        yield return lineBreak();
        yield return text(@"Le chasseur se tenait sur le perron de la Loge des Chasseurs, engoncé dans un manteau de cuir, une arbalète dans sa main gauche. Ses habits étaient maculés de sang. Les autres membres de la Fraternité à ses côtés brandissaient mousquets, haches, et pistolets, ainsi que les trophées décapités des monstres tués dans les terres sauvages. Ils revenaient de la chasse.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("L\'homme à leur tête s\'adressa à la foule, les yeux presque dissimulés par son cha" +
            "peau :");
        yield return lineBreak();
        yield return text(@"« Plus jamais cette grande ville ne sera forcée de subir tel outrage ! Nous, la Fraternité des Chasseurs, combattrons les bêtes de la forêt. Les responsables de ces pestilences impures, ce sont les monstres qui nichent dans nos collines ! Avec votre assistance, nous exterminerons cette vermine, nous les renverrons en enfer. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le discours provoqua des vivats de joie et ainsi fut établi le règne de la Frater" +
            "nité. Une modeste « taxe » fut instaurée pour aider à l\'effort de chasse, et pas" +
            " un citoyen ne sourcilla à s\'en acquitter.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "CharityNegCons", null);
        yield break;
    }


    // .............
    // #191: EvilHunter1EventYes

    void passage191_Init()
