    IStoryThread passage191_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Préparer un concours");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La famille passa des mois à voyager, sous la lueur du soleil et celle de la lune, sans entendre le moindre mauvais présage ni le moindre hurlement bestial. Pour ces esprits scientifiques, il était clair que ces invasions venues des enfers n'étaient rien de plus que le produit d'imaginations trop fertiles. Sans hésiter, ils soumirent des accusations à la ");
        using (styleScope("bold", true))
        {
            yield return text("Fraternité des chasseurs");
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Après un échange mi-moqueur, mi-exaspéré, il fut décidé que la Fraternité devrait donner preuve de ses exploits surnaturels en affrontant les monstruosités maudites les soirs, mais au vu et au su de tous les citadins. Un grand festival serait organisé autour de ce concours, sous la bénédiction d'une lune écarlate. Ils iraient ensemble dans les collines maudites et reviendraient avec plus de trophées que jamais. Mais, si leur chasse devait être couronnée de succès, alors les scientifiques leur seraient endettés... et devraient payer ");
        using (styleScope("bold", true))
        {
            yield return text("les intérêts");
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les cousins acceptèrent les termes, tout en ourdissant une machination insidieuse" +
            ". Ils ricanaient méchamment et ouvertement. Si les Chasseurs voulaient vivre une" +
            " vraie chasse de primes, alors ils l\'auraient !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "GloomyGothic2", null);
        yield return lineBreak();
        yield break;
    }


