    IStoryThread passage192_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Le grand concours - Avril 1902");
        }
        yield return lineBreak();
        yield return text("Après des années d\'excuses et de malencontreux reports, la ");
        using (styleScope("bold", true))
        {
            yield return text("Fraternité des Chasseurs");
        }
        yield return text(" ");
        yield return text("dut enfin se soumettre à la nuit du Grand Concours. On avait parlé de cette confr" +
            "ontation dans la région tout entière, et les badauds d\'ici et d\'ailleurs se mass" +
            "aient autour de la Loge de ");
        yield return text(Vars.townname);
        yield return text(". On acclama les Chasseurs, on leur lança des serpentins de papier, on leur offri" +
            "t un festin. Mais, dès que l\'après-midi fut passé, et que le ciel était embrasé " +
            "des lueurs du crépuscule, les célébrations s\'arrêtèrent.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les Chasseurs revêtirent leurs uniformes traditionnels, brandirent leurs armes bi" +
            "en fourbies, et descendirent l\'artère principale sous la lumière de la lune de s" +
            "ang avant de prendre la direction des forêts lointaines.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le même feu écarlate brûlait dans les yeux des scientifiques, qui avaient du mal à retenir des éclats de rire sinistres. La nuit précédente, les cousins avaient préparé leurs Expériences pour les lâcher dans les terres sauvages. Ce soir, les Chasseurs allaient devenir les proies !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour résoudre l\'événement...", "CannotParticipate", null);
        yield break;
    }


