            " de ");
        yield return text(Vars.townname);
        yield return text(". S\'étant débarrassé du mal qui infestait les institutions locales, la ville conn" +
            "ut une période de paix qui fut particulièrement productive pour un certain group" +
            "e de scientifiques.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage193_Fragment_1);
