        using (styleScope("bold", true))
        {
            yield return text("Guidés par la science");
        }
        yield return lineBreak();
        yield return text(@"À la requête des administrateurs de l'université, il fut décidé de faire figurer plus de travaux provenant d'inventeurs du cru. Cependant, l'administration trouva malavisé de promouvoir le travail de ceux qui avaient déjà profité de la lumière : il s'agissait de promouvoir tout le monde de façon “équitable” en rehaussant les noms les moins connus, afin d'afficher l'étendue des ambitions scientifiques entretenues à ");
        yield return text(Vars.townname);
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les cousins furent dégoûtés de cette assistance indue et maladroite, mais acceptè" +
            "rent néanmoins la décision, laissant le membre de la famille le plus éminent gro" +
            "gner devant l\'injustice du procédé.");
