    // .............
    // #203: UniEvent1-UltimateDisease

    void passage203_Init()
    {
        this.Passages[@"UniEvent1-UltimateDisease"] = new StoryPassage(@"UniEvent1-UltimateDisease", new string[] { }, passage203_Main);
    }

    IStoryThread passage203_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Ignorés par l\'élite scientifique");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le cœur plein de ressentiment, les ");
        yield return text(Vars.playtxt);
        yield return text(" ");
        yield return text(@"cousins observaient les rues autrefois moroses, aujourd'hui décorées aux couleurs vives du printemps. Des familles de classe moyenne, désormais bien éduquées, se promenaient sur les trottoirs dans leurs habits modestes. Les enfants riaient, faisaient des tours de draisienne dans le parc. Ce spectacle fit frissonner les cousins. Tout cela était « trop bon ».");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les festivités étant terminées, ils étaient tenus en moins bonne estime aux yeux des universitaires. Ils n'étaient ni maltraités ni méprisés, mais l'enthousiasme généreux de jadis avait souffert des multiples infractions commises, allant de la violation des codes éthiques à la dégradation de l'amphithéâtre opératoire en passant par les piques de colère lors des colloques. Pis encore, il devient de plus en plus clair qu'au vu des valeurs progressistes et paisibles portées par ");
        yield return text(Vars.townname);
        yield return text(", les gens éduqués étaient moins troublés par les soucis existentiels, immédiats " +
            "ou même d\'ordre diabolique.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La solution à ce manque de problèmes était évidente. Si le monde se refusait à créer une atrocité à laquelle il fallait donner réponse, alors les cousins défieraient la nature et la créeraient par eux-mêmes. S'ils combinaient leurs efforts, ils pourraient créer la ");
        using (styleScope("bold", true))
        {
            yield return text("maladie ultime");
        }
        yield return text(" ");
        yield return text("! Une maladie si infectieuse qu\'elle vaincrait pour de bon cette épidémie de posi" +
            "tivité.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cela leur permettrait certainement de ");
        using (styleScope("bold", true))
        {
            yield return text("se débarrasser du nivellement injuste");
        }
        yield return text(" ");
        yield return text("des fortunes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "UniCharity", null);
        yield break;
    }


