        ViewSpecialEvent.instance.ShowEventPopup();
        yield return text("Les rais du soleil, si oppressants, illuminaient l\'étude de ");
        if (Vars.players == 2)
        {
            yield return text(macros1.either(Vars.nameA, Vars.nameB));
        }
        if (Vars.players == 3)
        {
            yield return text(macros1.either(Vars.nameA, Vars.nameB, Vars.nameC));
        }
        if (Vars.players == 4)
        {
            yield return text(macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD));
        }
        if (Vars.players == 5)
        {
            yield return text(macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE));
        }
        yield return text(" ");
        yield return text(@"troisième du nom. Les cousins étaient rassemblés pour finaliser leur création. Un grand morceau de vélin était étalé sur le bureau, calé par des assiettes remplies de strudels à la crème fraîche ; l'outil parfait pour deviser un plan en utilisant toutes les connaissances acquises lors de leurs récentes expérimentations.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Certains, cependant, étaient moins enclins à partager les informations que d\'autr" +
            "es.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("VOTEZ");
        }
        yield return lineBreak();
        yield return text(@"Les joueurs vont maintenant voter pour collaborer en offrant leurs connaissances afin de créer une nouvelle maladie. Tous les joueurs se munissent de leur jeton Vote et le placent dans leur main. Les joueurs choisiront secrètement un côté et ferment le poing. Lorsqu'ils sont prêts, ils avancent la main au centre de la table.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Un vote ");
        using (styleScope("bold", true))
        {
            yield return text("Oui");
        }
        yield return text(" ");
        yield return text("révélé vous fait défausser ");
        using (styleScope("bold", true))
        {
            yield return text("1 expérience de chimie ou d\'occultisme achevée");
        }
        yield return text(".");
        yield return lineBreak();
        yield return text("Un vote ");
        using (styleScope("bold", true))
        {
            yield return text("Non");
        }
        yield return text(" ");
        yield return text("révélé représente votre décision de NE PAS contribuer en fournissant une expérien" +
            "ce.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Lorsque tous les joueurs ont fait leur choix, ils révèlent leur vote simultanémen" +
            "t. Comptabilisez tous les votes. Le côté avec le plus de votes gagne. ");
        using (styleScope("bold", true))
        {
            using (styleScope("italic", true))
            {
                yield return text("En cas d\'égalité, le \"oui\" l\'emporte.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        //yield return link("Cliquez ici pour procéder au vote.", "UniEvent2-UltimateDisease2", null);
        using (styleScope("hook", "h0000204"))
            yield return link("Cliquez ici pour procéder au vote.", null, () => enchantHook("h0000204", HarloweEnchantCommand.None, passage204_Fragment_0));

        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
