    // #205: UniEvent2-Success

    void passage205_Init()
    {
        this.Passages[@"UniEvent2-Success"] = new StoryPassage(@"UniEvent2-Success", new string[] { }, passage205_Main);
    }

    IStoryThread passage205_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un merveilleux succès");
        }
        yield return lineBreak();
        yield return text(@"Symptômes : nausée, fièvre, vomissements, hypertension, somnolences, perte de libido, lésions cutanées, vision trouble, palpitations cardiaques, céphalées, perte de poids, douleurs chroniques, possession démoniaque. Sur le papier, la Maladie Ultime collectionnait tout effet listé par la science. Les cousins passèrent une bonne partie de la nuit à concocter l'élixir, riant jusqu'à ce que la gorge leur fasse mal.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La semaine suivante, la maladie se répandit à la halle du marché. Une fiole de la décoction infâme fut brisée sur les marches de l'établissement. En quelques secondes, le fléau se répandait déjà, les aérosols se communiquant d'une personne à l'autre à chaque quinte de toux.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cependant, l'effet ne fut pas celui escompté. L'amalgame de maladies mortelles, bien qu'il causât quelques symptômes mineurs chez les premiers infectés, renforça les anticorps des habitants de la région, rendant leur système immunitaire plus apte à lutter contre les infections. En créant une maladie qui contenait tous les symptômes possibles, ils avaient vacciné la populace contre toutes les maladies simultanément.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"L'université ne mit pas longtemps à trouver l'origine du phénomène, c'est-à-dire les cousins. Le bouche-à-oreille fonctionna vite, et bientôt, on célébra ce nouveau triomphe pour la science et pour le monde ! Clairement, cette famille de scientifiques n'avait pas besoin d'aide pour répandre le bien autour d'elle.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage205_Fragment_2);
        using (styleScope("hook", "h000020502"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000020502", HarloweEnchantCommand.Replace, passage205_Fragment_1));

        yield break;
    }

