    }

    IStoryThread passage206_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Échec malencontreux");
        }
        yield return lineBreak();
        yield return text(@"Les cousins gardant leurs connaissances pour eux, sans consensus pour les faire avancer ensemble, la réunion tourna au vinaigre et au chacun pour sa peau. On entamait de grands discours pour se faire mousser et souligner la jalousie que les autres éprouvaient. Les pâtisseries, ce soir-là, ne connurent pas un succès retentissant.");
        yield return lineBreak();
