    IStoryThread passage214_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un message");
        }
        yield return lineBreak();
        yield return text(@"Une nouvelle décennie commençait. La parade d'horreurs bestiales et chamarrées n'usait plus de ses griffes pour détruire : l'on préférait, avec, créer. Les monstres se conformaient aux modes modernes et utilisaient les lieux communs comme tout le monde, avançant dans les rues la tête haute. La ville, elle, continuait à prospérer.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Pour la majorité, cependant, ce nouveau sens de paix était terni par l\'ombre des " +
            "injustices passées. Les tirages de journaux devinrent monnaie courante et, ainsi" +
            ", de plus en plus de pétitions et de pamphlets circulèrent parmi la populace.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« Nos parents furent frappés, massacrés, on expérimenta sur eux. C\'en est trop ! " +
            "Nous ne supporterons plus cette injustice, disait un brûlot. La viande, c\'est un" +
            " meurtre. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La plupart avaient adopté un régime pythagoricien, développant une appétence particulière pour les currys de légumes et toutes sortes de gruaux. Il n'était pas strictement interdit de consommer la chair cuite des animaux domestiques, mais lorsque les cousins ou leur suite s'arrêtaient chez le boucher du marché, les citadins les contemplaient, horrifiés. Les mères plaçaient la main sur les yeux de leurs enfants, comme si les conséquences des actes commis ici étaient trop sinistres pour eux.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Et pourtant, sous le mince vernis de cette étiquette guindée, une nature plus pri" +
            "male s\'éveillait, prête à émerger à nouveau.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage214_Fragment_1);
        using (styleScope("hook", "h000021401"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000021401", HarloweEnchantCommand.Replace, passage214_Fragment_0));

        yield break;
    }

