    // #215: AngryMobStorybook

    void passage215_Init()
    {
        this.Passages[@"AngryMobStorybook"] = new StoryPassage(@"AngryMobStorybook", new string[] { "ck2", "rev3", }, passage215_Main);
    }

    IStoryThread passage215_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Jour de terreur");
        }
        yield return lineBreak();
        Vars.amtoken = macros1.either(1, 2);
        Vars.gen3page = 1;
        yield return lineBreak();
        if (Vars.amtoken == 1)
        {
            yield return text("La rage des citadins s\'accumulait, s\'accumulait, et, à un moment, finissait par e" +
            "xploser en effusions incontrôlables. Pour les monstres de ");
            yield return text(Vars.townname);
            yield return text(", ce n\'était plus une question de fourches et de torches brandies, mais de soif d" +
            "e sang fébrile.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Par un dimanche après-midi des plus tranquilles, un loup-garou local ôtait son ch" +
            "apeau et s\'asseyait à une table, interrompant l\'heure du thé, un lambeau de tiss" +
            "u croûté de sang séché en main.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Il déposa le tissu sur la table avant de prononcer le moindre mot. Puis il éleva " +
            "une voix penaude, les oreilles rabattues :");
            yield return text("« Nous vous remettrions le corps pour qu\'il soit enterré proprement, si c\'était p" +
            "ossible. Mais vous savez ce que c\'est, quand il y a des os... Désolés. »");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Un autre servant avait disparu. C\'était inévitable, mais c\'était une perte de tem" +
            "ps et d\'argent.");
        }
        if (Vars.amtoken == 2)
        {
            yield return text("Être réveillé aux aurores après une dure nuit de travail, voilà qui était déjà pé" +
            "nible. Mais alors se réveiller au son d\'un hurlement suraigu, c\'était une autre " +
            "affaire.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Une femme vêtue d'une robe bleue et quelconque était accroupie près de l'entrée du domaine, fermant sa mâchoire couverte de sang tenue de ses mains griffues tout en hurlant sa détresse à pleins poumons. À quelques mètres se tenaient deux loups à la mise élégante, penchés sur le corps d'un domestique, arrachant la chair à grands coups de crocs et de griffes. Une flaque de sang commençait à imbiber les graviers.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Un monstre se tenait à proximité, résistant visiblement à la tentation de se joindre à la curée. Il tritura sa cravate et essuya la salive qui dégoulinait de son menton avant de s'exprimer : « La pauvrette, elle n'a pas pu se contrôler. Elle a plongé ses dents dans la chair... Quelle tragédie ! Je suis vraiment, vraiment désolé. »");
            yield return text("La proximité des hommes et des loups devait indubitablement mener à ce genre d\'év" +
            "énement...");
        }
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour revenir en arrière...", passage215_Fragment_2);
        using (styleScope("hook", "h000021502"))
            yield return link("Cliquez pour revenir en arrière...", null, () => enchantHook("h000021502", HarloweEnchantCommand.Replace, passage215_Fragment_1));

        yield break;
    }

