    // #216: GoodFrenzyEvent

    void passage216_Init()
    {
        this.Passages[@"GoodFrenzyEvent"] = new StoryPassage(@"GoodFrenzyEvent", new string[] { }, passage216_Main);
    }

    IStoryThread passage216_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une proposition raisonnée");
        }
        yield return lineBreak();
        yield return text(@"La réforme concernant les monstres était altruiste, mais pas parfaite. On nota quelques infractions au cours des années, passant de la simple agression griffue à des arrachages de jugulaire par voie dentaire, et des épisodes de folie furieuse qui suivaient invariablement ces incidents.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il devint clair que les humains étaient légèrement ennuyés par la disparition de bétail et d'humains... du fait du régime des loups dans les deux cas. Il était aussi clair que chaque monstre avait, presque quotidiennement, de terribles pulsions à réprimer.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Peut-être, suggéra-t-on, pouvait-on leur permettre de satisfaire leurs sombres besoins dans un espace circonscrit où l'expression de toute violence serait encouragée. Ainsi en se déchaînant à des endroits et des moments plus propices, leurs pulsions seraient calmées.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Cliquez ici pour continuer...", "2p-FrenzyALT", null);
        }
        else
        {
            yield return link("Cliquez ici pour continuer...", "GoodFrenzyEvent2", null);
        }
        yield return lineBreak();
        yield break;
    }


