    // #217: YesFrenzy

    void passage217_Init()
    {
        this.Passages[@"YesFrenzy"] = new StoryPassage(@"YesFrenzy", new string[] { }, passage217_Main);
    }

    IStoryThread passage217_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La Frénésie");
        }
        yield return lineBreak();
        yield return text(@"Les citadins qui choisissaient de ne pas participer verrouillaient bien leur porte et barricadaient leurs fenêtres. Des hurlements de joie à vous glacer le sang annoncèrent la couleur, et les individus qui autrefois griffaient les murs sortirent de chez eux. La Frénésie n'épargna personne à ");
        yield return text(Vars.townname);
        yield return text(@". L'horrible spectacle fit grincer des dents, et alluma deux brasiers : un, de fureur, dans le cœur des citadins, et l'autre, dans les rues, où des maisons partaient en fumée, dévorées par de longues langues de feu. Lorsqu'une porte était enfoncée ou qu'une fenêtre volait en éclats, on avait à peine le temps d'entendre un cri étranglé avant que la Frénésie fasse couler le sang d'une personne de plus.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"S'adonner à autant de turpitudes ne fit rien pour calmer les pulsions réprimées des citoyens lupins. Bien au contraire. Dans les semaines qui suivirent, les habitants hybrides perdirent toute raison. Dans leur esprit, ne restait qu'un puits insondable débordant de colère et de sauvagerie, tant et si bien que la terre s'assombrit et devint amère !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le délicat équilibre entre la civilité et la sauvagerie avait été rompu. Les mons" +
            "tres pouvaient rôder dans la région et asseoir leur règne de terreur sur les mas" +
            "ses innocentes.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h00174"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h00174", HarloweEnchantCommand.Replace, passage217_Fragment_0));
        yield return lineBreak();
        yield break;
    }

