    // .............
    // #223: Preface-TCOD

    void passage223_Init()
    {
        this.Passages[@"Preface-TCOD"] = new StoryPassage(@"Preface-TCOD", new string[] { }, passage223_Main);
    }

    IStoryThread passage223_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Avant-propos");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Au sein de ces documents repose le récit détaillé d\'une certaine lignée. Cette hi" +
            "stoire s\'étend sur plusieurs générations, et, j\'en suis certain, continuera à fa" +
            "sciner les historiens pendant des années.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"J'ai tenté de relater les faits de la façon la plus académique possible, afin de pallier les contradictions des témoignages que j'ai pu collecter – ah, les affres des ouï-dire ! Bien que de nombreux détails puissent hanter l'imagination et repousser les limites de l'entendement humain, j'ai bon espoir que ce texte et les recherches jointes soient d'eux-mêmes tenus pour vrais. Les événements relatés, à la fois abominables et potentiellement surnaturels, ont la capacité d'ébranler les fondations du monde scientifique actuel.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Tout en remerciant la fondation qui m\'a commandé ce travail, et ce, bien que je n" +
            "\'aie jamais rencontré mes généreux bienfaiteurs, je soumets humblement ce travai" +
            "l biographique dans son entièreté, et j\'en atteste de la véracité sur mon honneu" +
            "r.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Votre dévoué");
        yield return lineBreak();
        yield return text("Dr. Ensign Benwallis");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "Scenario5Start", null);
        yield break;
    }


