        using (styleScope("bold", true))
        {
            yield return text("L\'Œuvre touche à sa fin");
        }
        yield return lineBreak();
        Vars.gen3pg = 1;
        yield return lineBreak();
        yield return text(@"Les monstruosités bardées de griffes célébrèrent l'accomplissement du Grand Œuvre à grand renfort de cris perçants. L'héritage de la famille serait éternel, enfin ! Les regards vitreux de la foule assemblée ne partageaient pas cette déférence et ces sentiments.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Des grognements résonnèrent, pareils à un orage furieux, tandis que les monstres encerclaient l'expérience. Certains prenaient des notes, copiaient les plans et les formules aussi rapidement que possible, quand d'autres observaient avec intérêt ou traçaient du doigt les contours du moindre détail.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il était clair que, pour peu que l\'on eût donné accès aux travaux des cousins des" +
            " années auparavant, les bêtes auraient été à même de les comprendre plus profond" +
            "ément et d\'en reproduire les résultats.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez ici pour revenir en arrière...", passage228_Fragment_1);
        using (styleScope("hook", "h000022801"))
            yield return link("Cliquez ici pour revenir en arrière...", null, () => enchantHook("h000022801", HarloweEnchantCommand.Replace, passage228_Fragment_0));

        yield break;
    }

