    // .............
    // #229: Evilsforgive

    void passage229_Init()
    {
        this.Passages[@"Evilsforgive"] = new StoryPassage(@"Evilsforgive", new string[] { }, passage229_Main);
    }

    IStoryThread passage229_Main()
    {
        if (Vars.society == "Société de Saint Hubertus")
        {
            using (styleScope("bold", true))
            {
                yield return text("Pardon");
            }
            yield return lineBreak();
            yield return text(@"Les doutes des scientifiques furent calmés lorsqu'un loup-garou en costume de ville brun s'avança sur l'estrade pour présider une session du conseil municipal. Une foule hétéroclite de lycanthropes, de bêtes cornues et d'êtres s'accrochant encore à leur forme humaine se massait devant l'école. La puissance des mots du loup leur arracha des larmes.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"« Nous voulons faire voler en éclats ces malencontreux stéréotypes. Nous ne sommes pas rancuniers. Nous voulons travailler avec vous, et non pas contre vous. On ne punit pas un enfant pour les péchés de son père. Tout le monde sera accueilli. » Ému, le loup-garou se moucha sous le tonnerre d'applaudissement et de vivats qui s'ensuivit.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("De nombreuses poignées de main furent échangées en ce jour où les mythes perdiren" +
            "t de leur substance. On promit d\'avancer vers une nouvelle ère, une ère dans laq" +
            "uelle la science améliorerait drastiquement la vie de tout un chacun !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage229_Fragment_1);
            using (styleScope("hook", "h000022901"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000022901", HarloweEnchantCommand.Replace, passage229_Fragment_0));

        }
        if (Vars.society == "Fraternité des Chasseurs")
        {
            if (Vars.hcount == 0 || Vars.hcount == "")
            {
                yield return abort(goToPassage: "EquitableValues");
            }
            else
            {
                using (styleScope("bold", true))
                {
                    yield return text("Toujours méfiants");
                }
                yield return lineBreak();
                yield return text(@"Les soirs, la Fraternité se rassemblait dans l'ancienne mairie et célébrait la prise de contrôle de la petite bourgade. On entendit les vivats et les festivités jusque tard dans la nuit dans les rues avoisinantes. Les citadins n'avaient aucune raison de douter de leur loyauté, puisqu'il apparaissait que les activités de la Fraternité avaient éloigné d'eux la maladie et les superstitions.");
                yield return lineBreak();
                yield return lineBreak();
                yield return text(@"Pour les membres de la famille qui les avaient assistés, ils affichaient des sourires rayonnants mais fallacieux, levaient des toasts à leur partenariat, si continu. Mais à l'encontre de ceux qui avaient comploté contre eux, ils demeuraient toujours méfiants.");
