    // .............
    // #230: SymposiumMiddle

    void passage230_Init()
    {
        this.Passages[@"SymposiumMiddle"] = new StoryPassage(@"SymposiumMiddle", new string[] { }, passage230_Main);
    }

    IStoryThread passage230_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un remède pour la Fièvre jaune");
        }
        yield return lineBreak();
        Vars.midquote = macros1.either(1, 2, 3);
        yield return lineBreak();
        yield return text("« Vague et sordide à la fois. » Les notes des cours magistraux dépeignaient des r" +
            "éactions pour le moins diversifiées. ");
        if (Vars.midquote == 1)
        {
            yield return text("« N\'est qu\'ambition et rébellion, sans respect pour l\'éthique traditionnelle ni l" +
            "a méthode scientifique. Des hypothèses infondées, et une conclusion hâtive, homé" +
            "opathique au mieux. »");
        }
        if (Vars.midquote == 2)
        {
            yield return text("« Une intervention curieuse, mais peu mature. J\'ai noté une citation bien particu" +
            "lière pour la postérité, afin que nos pairs puissent en profiter, une fois que j" +
            "e l\'aurai placardée dans les toilettes de l\'université. Voici cette citation :");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("\"L\'affaire est toute simple. Lavez-vous simplement les mains après vous être torc" +
            "hé le cul.\" »");
        }
        if (Vars.midquote == 3)
        {
            yield return text("« Délicieusement brut, mais pourrait s\'avérer intéressant. Leurs cours magistraux" +
            ", quoi que fort divertissants, manquaient cruellement de substance. »");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"L'assemblée semblait intriguée... au début. Mais les présentations, bien que passionnantes, ne trouvèrent pas pour autant grâce à ses yeux, car de valeur scientifique trop piètre. Il fut décidé par la majorité de rechercher dans le portfolio des cousins d'autres découvertes notables avant de faire des recommandations.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.pub == "yes")
        {
            yield return text("Ce fut la ");
            using (styleScope("bold", true))
            {
                yield return text("publication");
            }
            yield return text("d\'un papier sur l\'inoculation de la ");
            using (styleScope("bold", true))
            {
                yield return text("Fièvre jaune");
            }
            yield return text("ayant eu lieu dans une ville hongroise autrement inconnue qui fit pencher la bala" +
            "nce en faveur de la construction d\'une université dans la région.");
            yield return lineBreak();
            yield return lineBreak();
            yield return link("Cliquez ici pour continuer...", "SymposiumSuccess", null);
        }
        else
        {
            yield return text("Et sans la publication d\'un papier sur l\'inoculation de la ");
            using (styleScope("bold", true))
            {
                yield return text("Fièvre jaune");
            }
            yield return text(", la décision de ne pas construire d\'université dans une ville hongroise de secon" +
            "de zone était facile à prendre.");
            yield return lineBreak();
            yield return lineBreak();
            yield return link("Cliquez ici pour continuer...", "SymposiumFail", null);
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


