            yield return lineBreak();
            yield return text(@"L'hôpital sombrant dans la vétusté, l'église prit des mesures et avertit la population de l'inoculation, préférant promouvoir les vertus des remèdes homéopathiques et la pratique quotidienne de la prière. Inévitablement, des foyers de Fièvre jaune éclatèrent dans la région.");
