    // .............
    // #248: 3ExperimentsRes

    void passage248_Init()
    {
        this.Passages[@"3ExperimentsRes"] = new StoryPassage(@"3ExperimentsRes", new string[] { }, passage248_Main);
    }

    IStoryThread passage248_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Avancées en ");
            yield return text(Vars.sci3);
        }
        yield return lineBreak();
        yield return text(@"Les années progressant, leurs expériences devinrent de plus en plus spécialisées. Il n'était pas rare que les membres de la famille soumettent des découvertes dans des journaux scientifiques ou médicaux. La plupart des sujets étaient sommairement rejetés, mais ce constant flux de soumission valut aux cousins des visites intéressées.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Une de ces visites se déroula au laboratoire de ");
        yield return text(Vars.gen2exp);
        yield return text(". Les arrivants furent d\'abord terrorisés, mais ensuite, s\'intéressèrent de bien " +
            "plus près aux extrêmement complexes ");
        if (Vars.sci3 == "Biologie")
        {
            yield return text("appareillages emplis de produits chimiques colorés ainsi que de spécimens uniques" +
            " récupérés (et créés !) au fil des années.");
        }
        if (Vars.sci3 == "Chimie")
        {
            yield return text("labyrinthes de tuyaux de caoutchouc, aux collections de produits chimiques et aux" +
            " vaisseliers emplis de béchers de formes et de tailles diverses.");
        }
