    // #258: EvilWolvesEventStart

    void passage258_Init()
    {
        this.Passages[@"EvilWolvesEventStart"] = new StoryPassage(@"EvilWolvesEventStart", new string[] { }, passage258_Main);
    }

    IStoryThread passage258_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Le Monstre du dehors");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Au sein du QG de la Société de Saint Hubertus, au plus profond des caves renfermées, sous une cage d'escalier en colimaçon, les cousins trouvèrent une grande salle de pierre massive : un laboratoire enfoui si profondément que les murs étaient chauds. Des appareils de verre et des outils volés y étaient empilés sur des paillasses de bois rudimentaires, les rebuts d'expériences ratées et appareils dysfonctionnels jetés dans des corbeilles de métal.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le majordome du quartier général désigna le centre de la pièce d'une main griffue, indiquant un puits de pierre imposant. Lorsqu'ils regardèrent à l'intérieur, les cousins virent les incubateurs infernaux. Des créatures couvertes d'humeurs visqueuses se roulaient dans cette fosse qui exhalait des remugles de viande en putréfaction. Elles hurlèrent, en proie à un tourment invisible, lorsque les gardiens de la Société firent claquer des fouets pour forcer les horreurs difformes à se calmer.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le majordome éleva une voix rocailleuse et sèche :");
        yield return lineBreak();
        yield return text("« Vous êtes libres d\'utiliser cet endroit à votre guise. Tout ce que nous demando" +
            "ns de vous, c\'est une simple expérience de votre cru lorsque nous vous la demand" +
            "erons. Et nos enfants ont très, très faim... Ils ont toujours faim. »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ce don était des plus sombres, mais quel était le prix d\'un endroit en ville où ");
        using (styleScope("bold", true))
        {
            yield return text("achever des expériences");
        }
        yield return text(" ");
        yield return text("?");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "VialCharity", null);
        yield break;
    }


