    IStoryThread passage280_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une étude biologique particulière");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pendant cette période, les entrées de journal des cousins exhibaient une paranoïa croissante quant au travail robuste de leurs parents. Non seulement les scientifiques documentaient leur anxiété due à des critiques et une négativité constantes, mais, en sus, cette méfiance maladive était accrue par la peur qu'on leur sabote leurs expériences.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Certaines entrées datées des premiers mois de 1891 constituent, combinées, une étude de l'anatomie humaine. Dans ces pages, on peut y voir des fibres musculaires détaillées, des coupes montrant les veines et artères. L'âge du sujet est spécialement avancé, dépeignant un tableau exceptionnel de l'effet du temps sur l'organisme et le système sanguin.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ce n\'est que dans les dernières pages que le sujet jusqu\'ici anonyme est indiqué " +
            "comme décédé - se pourrait-il même qu\'il y ait plusieurs sujets ? La confusion d" +
            "emeure, mais, en tout cas, l\'entrée concernée indique :");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« Sujet décédé. Ces derniers mois, je crois m\'être rapproché de mon parent comme " +
            "jamais. Ah, si nous avions pu partager plus de temps ensemble ! Il reste tant à " +
            "apprendre. Le laboratoire est désormais baigné de silence... »");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "OptiontoKillYes", null);
        yield return lineBreak();
        yield break;
    }


