    IStoryThread passage289_Fragment_2()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un héritage charitable");
        }
        yield return lineBreak();
        yield return text("En inspectant le cellier, un tintement contre la pierre fit une drôle d\'impressio" +
            "n à ");
        yield return text(Vars.charity);
        yield return text(" ");
        yield return text("troisième du nom. La fiole tombée ne s\'était pas brisée, par chance, et elle cont" +
            "enait encore son liquide. L\'étiquette attachée à son bouchon de liège trahissait" +
            " l\'âge considérable de la concoction.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("On pouvait lire sur le papier : « Voici un cadeau : de l\'eau bénite d\'une église " +
            "rendant grâce à Dieu ». De l\'autre côté, on pouvait lire que le destinataire de " +
            "ce présent n\'était autre que ");
        yield return text(Vars.charity);
        yield return text(" ");
        yield return text("premier du nom. Cette fiole datait donc d\'actions charitables effectuées dans le " +
            "passé.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage289_Fragment_1);
        using (styleScope("hook", "h000028901"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000028901", HarloweEnchantCommand.Replace, passage289_Fragment_0));

        yield break;
    }

    IStoryThread passage289_Fragment_3()
    {
        yield return enchant("Une fois que vous êtes prêt, cliquez ici pour révéler votre conversation secrète." +
            "", HarloweEnchantCommand.Replace, passage289_Fragment_2);
        yield break;
    }

