        yield return text("En considérant ce moment, avec le recul, se dire qu\'un homme qui aurait pu faire " +
            "cesser cette immonde infestation avait choisi de tirer profit de la situation, v" +
            "oilà qui est pour le moins atroce. L\'abominable décision de ");
        yield return text(Vars.charity);
        yield return text(" ");
        yield return text("troisième du nom rendrait cette maladie qui affligeait la terre presque inarrêtab" +
            "le.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage290_Fragment_1);
        using (styleScope("hook", "h000029001"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000029001", HarloweEnchantCommand.Replace, passage290_Fragment_0));

        yield break;
    }

