    {
        using (styleScope("bold", true))
        {
            yield return text("La taxe des chasseurs");
        }
        yield return lineBreak();
        yield return text(@"La Fraternité tint une réunion en ville par une après-midi étouffante, rassemblant la majorité des citadins dans les murs de la Loge de la Fraternité, richement ornée de tentures de velours et des trophées empaillés des monstres et des bêtes occis dans les terres sauvages.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le meneur de la Fraternité, vêtu de son habituel manteau et chapeau large, éleva " +
            "la voix :");
        yield return lineBreak();
        yield return text("« Le progrès sans précédent que cette ville a vécu, elle le doit à notre protecti" +
            "on sans faille. Nous avons fait barrière à la maladie comme aux démons qui nous " +
            "hantent depuis leurs collines. Cependant, un progrès sans précédent... cela se p" +
            "aye. »");
