    // .............
    // #307: WolvesVote

    void passage307_Init()
    {
        this.Passages[@"WolvesVote"] = new StoryPassage(@"WolvesVote", new string[] { }, passage307_Main);
    }

    IStoryThread passage307_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une opportunité");
        }
        yield return lineBreak();
        ViewSpecialEvent.instance.ShowEventPopup();
        yield return text(@"Avec un cri suraigu, la violoniste cessa de jouer. Les convives tournèrent la tête pour voir quelle était la source de la commotion. Une créature difforme et couverte de touffes éparses de poils gris avait titubé jusqu'à la véranda orientale, et s'était accroupie près de la table à dîner. Il semblait que la créature s'était rendue ici parce qu'elle pensait être attendue, en présence de toute la famille.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"« Ne me craignez pas. Je ne suis pas votre ennemi. Par chance, j'ai trouvé une concoction de fleurs d'érigéron et de muscaris à toupet. Elle fut capable de couper ma faim insatiable. » Les babines de l'homme-canidé frémissaient à chaque mot, comme s'il était prêt à grogner. Et pourtant... dans ses yeux émeraude brillait une lumière d'espoir.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« Avec votre aide, nous pouvons soigner la vallée tout entière et aider à soigner" +
            " les horreurs que nous avons déchaînées ! »");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les cousins n\'avaient pas pour coutume d\'utiliser une invention qui n\'était pas d" +
            "e leur cru, mais prendre la décision de le faire permettrait d\'éviter l\'humiliat" +
            "ion de donner une de leurs précieuses découvertes à ces clébards pouilleux.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("VOTEZ");
        }
        yield return lineBreak();
        yield return text("Les joueurs vont voter pour savoir s\'ils utilisent cette concoction pour dompter " +
            "la furie des bêtes qui rôdent dans le pays.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Un ");
        using (styleScope("bold", true))
        {
            yield return text("Oui");
        }
        yield return text(" ");
        yield return text("est un vote pour tenter d\'utiliser la concoction.");
        yield return lineBreak();
        yield return text("Un ");
        using (styleScope("bold", true))
        {
            yield return text("Non");
        }
        yield return text(" ");
        yield return text("est un vote servant à refuser de l\'utiliser.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Tous les joueurs se munissent de leur jeton Vote et le placent dans leur main. Le" +
            "s joueurs choisiront secrètement un côté et ferment le poing. Lorsqu\'ils sont pr" +
            "êts, ils avancent la main au centre de la table.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Lorsque tous les joueurs ont fait leurs choix, ils révèlent leur vote simultanéme" +
            "nt. Comptabilisez tous les votes. Le côté avec le plus de votes gagne. ");
        using (styleScope("italic", true))
        {
            yield return text("En cas d\'égalité, le dernier joueur ayant joué son tour tranche.");
        }
        yield return lineBreak();
        yield return lineBreak();
        //yield return link("Cliquez ici pour procéder au vote...", "WolvesVote2", null);
        using (styleScope("hook", "h0000308"))
            yield return link("Cliquez ici pour procéder au vote...", null, () => enchantHook("h0000308", HarloweEnchantCommand.None, passage308_Fragment_0));

        yield return lineBreak();
        yield break;
    }

