    IStoryThread passage308_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Souvenez-vous du remède");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("C\'était pour le moins étrange. Le vote avait commencé et on semblait arriver à un" +
            "e majorité de vote pour l\'utilisation de la concoction, on se sentait un certain" +
            " besoin d\'aider la ");
        using (styleScope("bold", true))
        {
            yield return text("Société");
        }
        yield return text(". On essayait d\'approuver le vote de toute ses forces mais... le mot « non » étai" +
            "t le seul mot à parvenir à certaines lèvres.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Comment aurait-on pu deviner les conséquences des remèdes employés par leurs parents pour soigner leur maladie héréditaire ? Quelques instants plus tard, une fois l'irrémédiable fait, il leur était impossible de savoir pourquoi et comment ils avaient pu accepter un plan aussi horrible !");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("ACTION SPÉCIALE");
        }
        yield return lineBreak();
        yield return text("Tous les joueurs possédant une ");
        using (styleScope("bold", true))
        {
            yield return text("carte Maladie");
        }
        yield return text(" ");
        yield return text("dans leurs Expériences sées doivent ");
        using (styleScope("bold", true))
        {
            yield return text("retourner leur jeton vote sur la face Non");
        }
        yield return text(" ");
        yield return text("s\'il ne l\'était pas déjà.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Recomptez les votes.");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Cliquez sur le résultat de votre vote :");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez ici si vous avez décidé de soigner l\'affliction grâce à la concoction.", "WolvesVoteChange", null);
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez ici si vous avez voté Non.", "TheVialUse", null);
        yield return lineBreak();
        yield break;
    }


    // .............
    // #309: WolvesVoteChange

    void passage309_Init()
    {
        this.Passages[@"WolvesVoteChange"] = new StoryPassage(@"WolvesVoteChange", new string[] { }, passage309_Main);
    }

    IStoryThread passage309_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Vote pour le changement");
        }
        yield return lineBreak();
        Vars.vialuse = "yes";
        yield return lineBreak();
        yield return text(@"Le groupe décida que, d'ici une quinzaine de jours, les cousins produiraient un sérum assez puissant pour soigner le mal qui affligeait les terres. En utilisant un mélange de sang coagulé de la bête, de racine de ciguë et de borax, ils purent procéder à des tests sur des sujets peu consentants. Cependant, le produit s'avéra assez fort pour éliminer les effets de la transformation... ou pour éliminer le sujet lui-même.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le liquide fut introduit à la source du cours d\'eau qui serpentait à travers les " +
            "landes cendrées et ténébreuses qui enveloppaient la ville de ");
        yield return text(Vars.townname);
        yield return text(". Il se diffusa avec le courant comme une huile brillante, éclaircissant les eaux" +
            " boueuses après une effervescence surnaturelle.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Après moins d'un jour, les azalées qui autrefois parsemaient le paysage était toutes ouvertes, et le soleil baignait la vallée entière d'une lueur de miel. Les créatures qui restaient furent changées à jamais, et bien que toujours aussi hideuses, elles se promenaient, la tête haute, dans des mises toutes propres, redingotes et robes d'été, levant leur chapeau à quiconque voulait bien les saluer.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les membres de la Société qui refusèrent de se soumettre à cette beauté sublime et purificatrice fuirent au plus profond des collines, et on ne les revit plus jamais. Les cousins étaient de nouveau les êtres les moins conformistes de la ville, et retournèrent à leur œuvre sans plus attendre.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "VialSoldforLess", null);
        yield return lineBreak();
        yield break;
    }


