        {
            yield return text("Un souvenir à garder");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Grâce à la nature surprenamment affable et bonne de la famille de scientifiques p" +
            "ourtant connue pour son mauvais caractère, l\'affliction quitta le pays.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La fiole de cristal contenant l'eau bénite, si elle avait été semblé impotante jadis, ne l'était pas pour autant pour nos cousins. Et pourtant, l'objet est tout à fait notable. Cet objet d'artisanat bohémien était en effet d'un cristal datant du XVII° siècle et, avec le déclin de l'empire austro-hongrois, ce genre d'objet valait autant qu'un bijou.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Fort de cette opportunité, le cousin vendit donc cette fiole pour une somme consé" +
            "quente.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage310_Fragment_1);
        using (styleScope("hook", "h000031001"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000031001", HarloweEnchantCommand.Replace, passage310_Fragment_0));

