            Vars.huntresult = "success";
        }
        if (Vars.huntcount == 1)
        {
            Vars.huntresult = macros1.either("success", "failure");
        }
        if (Vars.huntcount == 0 || Vars.huntcount == "")
        {
            Vars.huntresult = "failure";
        }
        if (Vars.huntresult == "success")
        {
            using (styleScope("bold", true))
            {
                yield return text("Une destinée ");
                yield return text(macros1.either("merveilleuse", "juste"));
            }
            yield return lineBreak();
            yield return text(@"Une par une, on jeta les armes dans le coffre de bois. Le choc des glaives, des dagues et des masses résonna contre les voûtes de la loge des chasseurs. On nettoya sommairement les tricornes du sang qui les maculait, on pendit les fusils sur des râteliers au mur. Ensuite, la Chasse, prétendant que la soirée avait été des plus normales, partagea une bouteille de pálinka, un alcool qui n'avait son pareil pour brûler la gorge et brouiller les pensées.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("La Chasse demeurerait vigilante tant que les monstres ne seraient pas éradiqués d" +
            "es parages. Mais avec ");
            yield return text(Vars.huntcount);
            yield return text("chasse, le pire était passé. La chasse avait été couronnée de succès.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage316_Fragment_1);
            using (styleScope("hook", "h000031601"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000031601", HarloweEnchantCommand.Replace, passage316_Fragment_0));

        }
        if (Vars.huntresult == "failure")
        {
            using (styleScope("bold", true))
            {
                yield return text("Envahi par la horde de ");
                yield return text(macros1.either("démons", "monstres"));
            }
            yield return lineBreak();
            yield return text("Une lame de brouillard fendit la lune et bientôt, la vallée fut enveloppée dans u" +
            "n cocon laiteux et spectral.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Les citadins avaient placé le destin de ");
            yield return text(Vars.townname);
            yield return text("entre les mains d\'une bande de crétins habillés de cuir, assez bravaches pour se " +
            "confronter à des forces au-delà de leur compréhension. Les scientifiques, au bou" +
            "t du compte, rirent de cette démarche futile.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Les cousins contemplèrent le chaos, amers d'avoir tant perdu, en sécurité derrière les grilles de fer forgé de leur domaine alors que de la ville envahie de créatures montait une cacophonie de cris désespérés. Les scientifiques, depuis leur véranda, sirotaient un café fraîchement passé en songeant qu'en ville, les abominations de l'enfer exerçaient leur terrible influence. La Chasse avait échoué.");
            yield return lineBreak();
            yield return lineBreak();
            Vars.overrun = "yes";
            yield return link("Cliquez pour continuer...", "Prosperity3b", null);
        }
        yield return lineBreak();
        yield break;
