    // .............
    // #317: END-UniGood

    void passage317_Init()
    {
        this.Passages[@"END-UniGood"] = new StoryPassage(@"END-UniGood", new string[] { }, passage317_Main);
    }

    IStoryThread passage317_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Note de l\'éditeur - Août 1923 :");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Bonjour, Ensign,");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"J'ai jeté un œil au manuscrit que vous m'avez soumis, et je dois admettre qu'il est bien au-delà de mes attentes. Le prologue promet de hanter l'imagination et repousser les limites de l'entendement humain. Le récit lui-même, en revanche, fait preuve de cohésion et raconte une histoire quelque peu exaltante de scientifiques essayant de faire du monde un endroit meilleur. Je dois admettre que certains détails concernant les moyens d'atteindre ce but étaient sinistres et peu orthodoxes, mais, surtout, l'histoire me semble incomplète.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Si je puis vous paraphraser : une famille scientifique entre dans l\'arène politiq" +
            "ue et aide l\'église à grand renfort de donations charitables afin de faire édifi" +
            "er un hôpital. De cette décision découle la prospérité de la région");
        if (Vars.cured == 1)
        {
            yield return text("\", d\'ailleurs renforcée par la création d\'un remède sans précédent pour la Fièvre" +
            " jaune\".");
        }
        if (Vars.uni == "yes")
        {
            yield return text(" Après cela, un excellent colloque participa à l\'édification d\'une université dans" +
            " la région. ");
        }
        if (Vars.ultimate == "yes")
        {
            yield return text("Ils purent créer un vaccin fortuitement, éliminant ainsi toutes les maladies de l" +
            "a région. ");
        }
        yield return text("Enfin, leur travail a propulsé la Hongrie et ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text("au-devant de la scène internationale. Le récit apporte un regard positif, renforç" +
            "ant ainsi le potentiel de bien vendre sur le marché londonien.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Quelques recommandations : altérez les descriptions des premiers chapitres afin d" +
            "e renforcer le côté positif du récit. Omettez les horreurs et les éléments surna" +
            "turels. Proposez une fin plus joyeuse.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'ai hâte de lire votre récit une fois ces révisions effectuées.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Mathieu Rivero");
        }
        yield return lineBreak();
        yield break;
    }


