    // .............
    // #324: ProsperityWolvesIntro

    void passage324_Init()
    {
        this.Passages[@"ProsperityWolvesIntro"] = new StoryPassage(@"ProsperityWolvesIntro", new string[] { "INTRO", }, passage324_Main);
    }

    IStoryThread passage324_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III :");
            yield return lineBreak();
            yield return text("La Société percée à jour");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je tenterai de relater les événements tels qu\'ils me furent contés, bien que je c" +
            "omprenne pleinement les importantes répercussions que peuvent causer les connais" +
            "sances indicibles contenues dans ce récit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Une période de prospérité pouvait-elle émerger et fleurir, à la façon d'un lys qui s'ouvre dans l'ombre d'une pierre tombale ? Pouvait-elle s'épanouir et perdurer sur un terreau de maladie et de mort ? Une fois les maléfiques machinations révélées et mises au ban, la Société de Saint Hubertus répondit à ces questions existentielles, en proposant des réformes qui chassèrent la grisaille et la brume en ville. Les champs furent labourés et les marécages asséchés jusqu'à ce que les champs de betteraves soient couverts d'un tapis de fleurs, on favorisa le commerce avec les villes avoisinantes et on alla jusqu'à négocier une extension du réseau électrique national. Les jeunes héritiers, lorsqu'ils revinrent de l'université pour récupérer leur héritage, reconnurent à peine la bourgade dans laquelle ils avaient grandi.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mais bientôt, les motivations derrière leur détermination à améliorer la réputation de la Société devinrent claires. Lors d'une éclipse partielle, la lune, rouge sang, traversa le ciel, et alors ils se transformèrent révélant l'horreur qu'ils avaient gardée secrète des années durant. Ceux épargnés par le phénomène contemplaient l'abominable spectacle, hébétés.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les monstres existaient bel et bien.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mais les bêtes n'entretenaient pas de dégoût pour leur forme. Bien que leur corps soit plus monstrueux et animal qu'humain, avec des traits allongés et lupins, des griffes et des regards froids, les abominations demandèrent qu'on leur montre de la compassion. Ne devait-on pas célébrer ce qui nous rendait différents ? Ces différences, justement... n'étaient-elle pas ce qui nous permettait de nous souder, de progresser ensemble ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pour les monstres, chaque créature était spéciale, à sa façon, et ils étaient convaincus qu'un comportement raisonné pouvait dompter les pulsions de quiconque, homme comme bête. Cet espoir résidait dans leur cœur vide, et ils espéraient envoyer un message d'amour et d'acceptation à l'humanité tout entière.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Oh, pauvres malheureux, imbéciles que vous étiez !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Si les habitants humains s'étaient retrouvés en sous-nombre face à ces êtres cauchemardesques, ils auraient répliqué par la violence, mais, sans mouvement belligérant de quelque côté que ce soit... La ville revint à un semblant de normalité, les monstres conservant leur apparence infernale.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Jusqu\'à ce que les scientifiques reprennent le travail familial et attirent à nou" +
            "veau l\'attention de la Société, du moins...");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "GoodConsequences", null);
        yield return lineBreak();
        yield break;
    }


