    // .............
    // #331: END-HuntersEvil2

    void passage331_Init()
    {
        this.Passages[@"END-HuntersEvil2"] = new StoryPassage(@"END-HuntersEvil2", new string[] { }, passage331_Main);
    }

    IStoryThread passage331_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Éclipsés et exploités");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cette histoire peut receler quelques événements inconcevables qui font ployer les murs de l'imagination, mais, quoi qu'il arrive, reste un récit situé dans un temps et un lieu reculés. Cette relique d'une ère où régnaient pseudo-science et spéculation eut bien peu d'importance historique.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ce ne furent pas les expériences de ");
        yield return text(Vars.playtxt);
        yield return text(" ");
        yield return text(@"ambitieux scientifiques qui gravèrent les mémoires. En revanche, les Chasseurs, qui accumulèrent renommée, fortune et respect sur le dos des paysans superstitieux, cela reste un souvenir encore vif aujourd'hui. La maladie qui avait dévasté le pays fut ignorée, reléguée au rang d'esprit malin provenant du folklore, qui pouvait être repoussée grâce à l'éternelle vigilance de la Fraternité des Chasseurs dont la protection, bien entendu, avait un coût colossal.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pendant les années qui suivirent, la Fraternité et ses membres abandonnèrent la ville, partant occuper des postes plus lucratifs au sein du gouvernement. La société pas-si-secrète se retrouva bientôt propulsée au sein de l'aristocratie, contrôlant toutes les institutions hongroises depuis les ombres. Et la famille qui autrefois inspirait respect et admiration fut nommée à la tête de préfectures obscures, parsemée aux quatre vents, au travers du pays.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Si l\'on doit croire cette histoire, alors les connaissances découvertes par des g" +
            "énérations de scientifiques demeurent dans les manoirs délabrés qui surplombent " +
            "");
        yield return text(Vars.townname);
        yield return text(". Le labeur de la famille avait cessé.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Mathieu Rivero");
        }
        yield break;
    }


    // .............
    // #332: END-WolvesEvil2

    void passage332_Init()
    {
        this.Passages[@"END-WolvesEvil2"] = new StoryPassage(@"END-WolvesEvil2", new string[] { }, passage332_Main);
    }

    IStoryThread passage332_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("L\'emprise du mal");
        }
        yield return lineBreak();
        yield return text(@"J'écris ces derniers mots à la lueur de la chandelle, depuis un abri de mon cru, logé dans les fondations du manoir. Pour toute table, je dispose d'une mauvaise planche de cèdre. Je garde mes outils et ustensiles au-dessus du sol, qui peut vite être envahi par l'eau et les moisissures pendant mes fréquents séjours nocturnes. Certes, il ne s'agit que d'une plume émoussée, de l'encre, quelques fusains et un rouleau de papier. Il n'est plus sûr pour moi de dormir dans mon lit à la tombée de la nuit. Les créatures émergent des ombres soit pour se nourrir des dernières âmes courageuses demeurées en ce pays, soit pour les transformer en horreurs inimaginables.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Si j'avais su que mon travail pour documenter la généalogie nébuleuse d'une famille de scientifiques au succès médiocre m'emmènerait jusque dans l'œil de ce cyclone de noirceur ! J'espère que, lorsque j'aurai terminé ce récit (si tant est que je le puisse), ces mots seront une accusation formelle condamnant ces imbéciles, accointés avec des démons. Le monde doit savoir qui est responsable. Il doit savoir, et condamner ce groupe qui a, dans le même temps, choyé les ténèbres et bafoué la science !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Oh, j\'entends à nouveau les créatures ! Leurs griffes difformes grattent le parqu" +
            "et ! Maudit soit cet infernal œuvre entrepris par la famille : c\'est à lui que l" +
            "\'on doit le fléau éternel qui empoisonne cette terre.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Mathieu Rivero");
        }
        yield break;
    }


